    StreamingRuntimeConfig * pRunTimeStreamConfig = BoardRunTimeConfig_Get(
            BOARDRUNTIME_STREAMING_CONFIGURATION);

    SCPI_ResultInt32(context, (int) pRunTimeStreamConfig->ActiveInterface);
    return SCPI_RES_OK;
}

