254→/**
255→ * @brief Handles streaming tasks by checking available data and writing it to active communication channels.
256→ * 
257→ * This function continuously monitors the availability of Analog and Digital I/O data and streams it 
258→ * over active communication channels (USB, WiFi, SD). It encodes data in the specified format and writes 
259→ * the output to all active channels based on available buffer sizes.
260→ * 
261→ * @param runtimeConfig Pointer to the runtime configuration of the board, including streaming settings.
262→ * @param boardData Pointer to the data structure that contains the board's input/output data.
263→ * 
264→ * @note This function will return early if streaming is disabled or there is no data to process.
265→ */
266→
267→void streaming_Task(void) {
268→    // Enable FPU context saving for this task (required for ADC voltage conversion)
269→    portTASK_USES_FLOATING_POINT();
270→
271→     TickType_t xBlockTime = portMAX_DELAY;
272→    NanopbFlagsArray nanopbFlag;
273→    size_t usbSize, wifiSize, sdSize, maxSize;
274→    bool hasUsb, hasWifi, hasSD;
275→    bool AINDataAvailable;
276→    bool DIODataAvailable;
277→    size_t packetSize=0;    
278→    tBoardData * pBoardData = BoardData_Get(
279→            BOARDDATA_ALL_DATA,
280→            0);
281→     StreamingRuntimeConfig * pRunTimeStreamConf = BoardRunTimeConfig_Get(
282→            BOARDRUNTIME_STREAMING_CONFIGURATION);
283→    while(1) {
284→        ulTaskNotifyTake(pdFALSE, xBlockTime);
285→        
286→        AINDataAvailable = !AInSampleList_IsEmpty();
287→        DIODataAvailable = !DIOSampleList_IsEmpty(&pBoardData->DIOSamples);
288→
289→        if (!AINDataAvailable && !DIODataAvailable) {
290→            continue;
291→        }
292→       
293→        usbSize = UsbCdc_WriteBuffFreeSize(NULL);
294→        wifiSize = wifi_manager_GetWriteBuffFreeSize();
295→        sdSize = sd_card_manager_GetWriteBuffFreeSize();
296→
297→        // Single-interface streaming: only stream to the interface that initiated streaming
298→        // This prevents bandwidth overload at high sample rates
299→        switch (pRunTimeStreamConf->ActiveInterface) {
300→            case StreamingInterface_USB:
301→                hasUsb = (usbSize >= 128);
302→                hasWifi = false;
303→                hasSD = false;
304→                break;
305→            case StreamingInterface_WiFi:
306→                hasUsb = false;
307→                hasWifi = (wifiSize >= 128);
308→                hasSD = false;
309→                break;
310→            case StreamingInterface_SD:
311→                hasUsb = false;
312→                hasWifi = false;
313→                hasSD = (sdSize >= 128);
314→                break;
315→            case StreamingInterface_All:
316→            default:
317→                // Legacy mode: stream to all interfaces (may cause issues at high rates)
318→                hasUsb = (usbSize >= 128);
319→                hasWifi = (wifiSize >= 128);
320→                hasSD = (sdSize >= 128);
321→                break;
322→        }
323→
324→        // Override: If SD card logging is explicitly enabled, automatically enable SD output
325→        // Only allow USB+SD (not WiFi+SD, as they share the SPI bus)
326→        sd_card_manager_settings_t* pSDCardSettings =
327→            BoardRunTimeConfig_Get(BOARDRUNTIME_SD_CARD_SETTINGS);
328→        if (pSDCardSettings && pSDCardSettings->enable &&
329→            pSDCardSettings->mode == SD_CARD_MANAGER_MODE_WRITE) {
330→            // Only enable SD if we're not streaming to WiFi (SPI bus conflict)
331→            if (pRunTimeStreamConf->ActiveInterface != StreamingInterface_WiFi) {
332→                hasSD = (sdSize >= 128);
333→            }
334→        }
335→
336→        // Log streaming start info once for debugging
337→        static bool firstLog = false;
338→        if (!firstLog) {
339→            LOG_I("Streaming started: interface=%d, usbSize=%u, wifiSize=%u, sdSize=%u",
340→                  pRunTimeStreamConf->ActiveInterface, usbSize, wifiSize, sdSize);
341→            firstLog = true;
342→        }
343→
344→        // CRITICAL: Always encode to drain the sample queue, even if no outputs have space
345→        // This prevents queue backup which causes the deferred interrupt task to drop samples
346→        // If no outputs available, sample will be encoded then discarded (better than queue backup)
347→
348→        // Use maximum available space among all outputs for encoding (not just enabled ones)
349→        // This ensures we can always encode even if all outputs are temporarily full
350→        maxSize = 128;  // Minimum packet size
351→        if (usbSize > maxSize) maxSize = usbSize;
352→        if (wifiSize > maxSize) maxSize = wifiSize;
353→        if (sdSize > maxSize) maxSize = sdSize;
354→
355→        // Cap at BUFFER_SIZE to prevent encoder overflow
356→        if (maxSize > BUFFER_SIZE) maxSize = BUFFER_SIZE;
357→        
358→        nanopbFlag.Size = 0;
359→        nanopbFlag.Data[nanopbFlag.Size++] = DaqifiOutMessage_msg_time_stamp_tag;
360→
361→        if (AINDataAvailable) {
362→            nanopbFlag.Data[nanopbFlag.Size++] = DaqifiOutMessage_analog_in_data_tag;
363→        }
364→        if (DIODataAvailable) {
365→            nanopbFlag.Data[nanopbFlag.Size++] = DaqifiOutMessage_digital_data_tag;
366→            nanopbFlag.Data[nanopbFlag.Size++] = DaqifiOutMessage_digital_port_dir_tag;
367→        }
368→
369→        packetSize = 0;
370→        if (nanopbFlag.Size > 0) {
371→            if(pRunTimeStreamConf->Encoding == Streaming_Csv){
372→                DIO_TIMING_TEST_WRITE_STATE(1);
373→                packetSize = csv_Encode(pBoardData, &nanopbFlag, (uint8_t *) buffer, maxSize);
374→                DIO_TIMING_TEST_WRITE_STATE(0);
375→            }
376→            else if (pRunTimeStreamConf->Encoding == Streaming_Json) {
377→                DIO_TIMING_TEST_WRITE_STATE(1);
378→                packetSize = Json_Encode(pBoardData, &nanopbFlag, (uint8_t *) buffer, maxSize); 
379→                DIO_TIMING_TEST_WRITE_STATE(0);
380→            } else {   
381→                DIO_TIMING_TEST_WRITE_STATE(1);
382→                packetSize = Nanopb_Encode(pBoardData, &nanopbFlag, (uint8_t *) buffer, maxSize); 
383→                DIO_TIMING_TEST_WRITE_STATE(0);
384→            }
385→        }
386→        DIO_TIMING_TEST_WRITE_STATE(1);
387→        if (packetSize > 0) {
388→            if (hasUsb) {
389→                UsbCdc_WriteToBuffer(NULL, (const char *) buffer, packetSize);
390→            }
391→            if (hasWifi) {
392→                wifi_manager_WriteToBuffer((const char *) buffer, packetSize);
393→            }
394→            if (hasSD) {
395→                const uint8_t* p = buffer;
396→                size_t remaining = packetSize;
397→                size_t total_written = 0;
398→                unsigned int attempts = 0;
399→                const unsigned int max_attempts = 3;
400→
401→                while (remaining > 0 && attempts < max_attempts) {
402→                    size_t w = sd_card_manager_WriteToBuffer((const char *)p, remaining);
403→                    if (w == 0) {
404→                        // No progress, break to avoid tight loop
405→                        break;
406→                    }
407→                    total_written += w;
408→                    p += w;
409→                    remaining -= w;
410→                    attempts++;
411→                    if (remaining > 0) {
412→                        // Partial write, yield to give SD task a chance
413→                        taskYIELD();
414→                    }
415→                }
416→
417→                if (total_written != packetSize) {
418→                    LOG_E("SD: Write failed after %u attempts, expected=%u, written=%u",
419→                          attempts, (unsigned)packetSize, (unsigned)total_written);
420→                }
421→
422→                static bool sd_logged = false;
423→                if (!sd_logged) {
424→                    LOG_D("SD: Write completed, packetSize=%u, written=%u, attempts=%u",
425→                          (unsigned)packetSize, (unsigned)total_written, attempts);
426→                    sd_logged = true;
427→                }
428→            } else {
429→                static bool no_sd_logged = false;
430→                if (!no_sd_logged) {
431→                    LOG_D("SD: Write skipped - hasSD is false");
432→                    no_sd_logged = true;
433→                }
434→            }
435→        }
436→        DIO_TIMING_TEST_WRITE_STATE(0);
437→       
438→        
439→
440→    }
441→}
