443→void TimestampTimer_Init(void) {
444→    //     Initialize and start timestamp timer
445→    //     This is a free running timer used for reference -
446→    //     this doesn't interrupt or callback
447→
448→    if (gStreamingTaskHandle == NULL) {
449→        BaseType_t result = xTaskCreate((TaskFunction_t) streaming_Task,
450→                "Stream task",
451→                4096, NULL, 2, &gStreamingTaskHandle);
452→        if (result != pdPASS) {
453→            LOG_E("FATAL: Failed to create streaming_Task (4096 bytes)\r\n");
454→        }
455→    }
456→    if (gStreamingInterruptHandle == NULL) {
457→        BaseType_t result = xTaskCreate((TaskFunction_t) _Streaming_Deferred_Interrupt_Task,
458→                "Stream Interrupt",
459→                4096, NULL, 8, &gStreamingInterruptHandle);
460→        if (result != pdPASS) {
461→            LOG_E("FATAL: Failed to create _Streaming_Deferred_Interrupt_Task (4096 bytes)\r\n");
462→        }
463→    }
464→    
465→    TimerApi_Stop(gpStreamingConfig->TSTimerIndex);
466→    TimerApi_Initialize(gpStreamingConfig->TSTimerIndex);
467→    TimerApi_InterruptDisable(gpStreamingConfig->TSTimerIndex);
468→    TimerApi_CallbackRegister(gpStreamingConfig->TSTimerIndex, TSTimerCB, 0);
469→    TimerApi_PeriodSet(gpStreamingConfig->TSTimerIndex, gpRuntimeConfigStream->TSClockPeriod);
470→    TimerApi_InterruptEnable(gpStreamingConfig->TSTimerIndex);
471→    TimerApi_Start(gpStreamingConfig->TSTimerIndex);
472→
473→}
