 33→//#define TEST_STREAMING
 34→
 35→// Log queue full error every N drops to avoid flooding the log at high rates.
 36→// At 15kHz this means we log approximately once per 6.7ms during overflow.
 37→#define LOG_QUEUE_DROP_INTERVAL 100
 38→#define UNUSED(x) (void)(x)
 39→#ifndef min
 40→#define min(x,y) ((x) <= (y) ? (x) : (y))
 41→#endif // min
 42→
 43→#ifndef max
 44→#define max(x,y) ((x) >= (y) ? (x) : (y))
 45→#endif // max
 46→
 47→#define BUFFER_SIZE min(min(USBCDC_WBUFFER_SIZE, WIFI_WBUFFER_SIZE), SD_CARD_MANAGER_CONF_WBUFFER_SIZE)  //2048
 48→uint8_t buffer[BUFFER_SIZE];
