205→static void Streaming_Start(void) {
206→    if (!gpRuntimeConfigStream->Running) {
207→        // Clear any stale samples from previous streaming session to free heap
208→        AInPublicSampleList_t* pStale;
209→        while (AInSampleList_PopFront(&pStale)) {
210→            if (pStale != NULL) {
211→                AInSampleList_FreeToPool(pStale);  // Use pool instead of vPortFree!
212→            }
213→        }
214→
215→        // Clear encoding buffer once to prevent stale data artifacts in SD files
216→        memset(buffer, 0, BUFFER_SIZE);
217→
218→        TimerApi_Initialize(gpStreamingConfig->TimerIndex);
219→        TimerApi_PeriodSet(gpStreamingConfig->TimerIndex, gpRuntimeConfigStream->ClockPeriod);
220→        TimerApi_CallbackRegister(gpStreamingConfig->TimerIndex, Streaming_TimerHandler, 0);
221→        TimerApi_InterruptEnable(gpStreamingConfig->TimerIndex);
222→        TimerApi_Start(gpStreamingConfig->TimerIndex);
223→        gpRuntimeConfigStream->Running = 1;
224→    }
225→}
