 51→/**
 52→ * @brief Log if a filesystem operation took longer than expected.
 53→ *
 54→ * Call after FS operation completes to detect slow operations.
 55→ *
 56→ * @param startTick  Tick count before operation started
 57→ * @param operation  String describing the operation
 58→ * @param result     Result code from the operation (-1 typically means error)
 59→ */
 60→static inline void SD_CheckFsOpDuration(TickType_t startTick, const char* operation, int result) {
 61→    uint32_t elapsed = pdTICKS_TO_MS(xTaskGetTickCount() - startTick);
 62→    if (elapsed > SD_DEBUG_TIMEOUT_MS) {
 63→        LOG_E("[SD] HANG DETECTED: %s took %u ms (limit %u ms), result=%d",
 64→              operation, elapsed, SD_DEBUG_TIMEOUT_MS, result);
 65→    } else if (elapsed > 5000) {
 66→        // Also log warning for operations > 5 seconds (unusual but not critical)
 67→        LOG_I("[SD] Slow operation: %s took %u ms, result=%d", operation, elapsed, result);
 68→    }
 69→}
