 71→// Shared coherent buffer for all SD operations (write, read, list)
 72→// DMA-safe for SPI transfers. Mutually exclusive operations share this buffer.
 73→// Cache-line aligned for optimal DMA performance.
 74→static __attribute__((coherent, aligned(16))) uint8_t gSdSharedBuffer[SD_CARD_MANAGER_CIRCULAR_BUFFER_SIZE];
 75→
