 80→/**
 81→ * Helper function: Wait for USB buffer to drain before EOF/close
 82→ * Prevents race condition where EOF arrives before last data is processed
 83→ * Waits up to 50ms for USB buffer to be >50% drained
 84→ */
 85→static void sd_wait_usb_drain(void) {
 86→    TickType_t start = xTaskGetTickCount();
 87→    while ((xTaskGetTickCount() - start) < pdMS_TO_TICKS(50)) {
 88→        // If buffer is mostly drained, assume progress and exit
 89→        if (UsbCdc_WriteBuffFreeSize(NULL) > (USBCDC_WBUFFER_SIZE / 2)) {
 90→            break;
 91→        }
 92→        vTaskDelay(1);
 93→    }
 94→}
