185→/**
186→ * @brief Recursively lists files and directories, storing the output in a buffer.
187→ *
188→ * This function traverses the directory specified by `dirPath`, listing all files and directories
189→ * within it, including those in subdirectories. The output is formatted and stored in the buffer
190→ * pointed to by `pStrBuff`. It adjusts the buffer pointer and size during recursive calls to
191→ * ensure that data is appended correctly without overwriting existing content.
192→ *
193→ * @param[in]  dirPath     The path of the directory to list.
194→ * @param[out] pStrBuff    Pointer to the buffer where the output will be stored.
195→ *                         The buffer should be large enough to hold the expected output.
196→ * @param[in]  strBuffSize The total size of the buffer pointed to by `pStrBuff`.
197→ *
198→ * @return The total number of bytes written to `pStrBuff`.
199→ *
200→ * @note
201→ * - The function uses recursion to traverse subdirectories.
202→ * - It maintains a local `strBuffIndex` to keep track of the current position in the buffer.
203→ * - During recursive calls, the buffer pointer `pStrBuff` and buffer size `strBuffSize` are
204→ *   adjusted to prevent buffer overflows.
205→ * - If the buffer becomes full during execution, the function stops writing further data to prevent overflow.
206→ *
207→ * @warning
208→ * - Ensure that `strBuffSize` is sufficient to hold the entire output; otherwise, buffer overflows
209→ *   or incomplete output may occur.
210→ * - Be cautious with deeply nested directories, as excessive recursion can lead to stack overflow.
211→ *
212→ * @example
213→ * @code
214→ * uint8_t outputBuffer[1024];
215→ * size_t totalBytes = ListFilesInDirectory("/mnt/myDrive", outputBuffer, sizeof(outputBuffer));
216→ *
217→ * // Ensure null termination if needed
218→ * if (totalBytes < sizeof(outputBuffer)) {
219→ *     outputBuffer[totalBytes] = '\0';
220→ * } else {
221→ *     outputBuffer[sizeof(outputBuffer) - 1] = '\0'; // Ensure null termination
222→ * }
223→ *
224→ * printf("%s", outputBuffer);
225→ * @endcode
226→ */
227→// Callback function type for sending directory listing chunks
228→typedef void (*ListChunkCallback)(const uint8_t* data, size_t len);
229→
230→// Static callback for sending directory listing chunks
231→static void sd_listdir_send_chunk(const uint8_t* data, size_t len) {
232→    if (len > 0) {
233→        LOG_D("[SD] Sending chunk: %d bytes\r\n", (int)len);
234→        sd_card_manager_DataReadyCB(SD_CARD_MANAGER_MODE_LIST_DIRECTORY, (uint8_t*)data, len);
235→    }
236→}
237→
238→static void ListFilesInDirectoryChunked(const char* dirPath, uint8_t *pStrBuff, size_t strBuffSize, ListChunkCallback sendChunk) {
239→    SYS_FS_FSTAT stat;
240→    size_t strBuffIndex = 0;
241→    SYS_FS_HANDLE dirHandle;
242→    char newPath[SD_CARD_MANAGER_FILE_PATH_LEN_MAX + 1];
243→
244→    memset(newPath, 0, sizeof (newPath));
245→    memset(&stat, 0, sizeof (stat));
246→    LOG_D("[SD] ListFiles: Opening directory '%s'\r\n", dirPath);
247→    dirHandle = SYS_FS_DirOpen(dirPath);
248→    if (dirHandle == SYS_FS_HANDLE_INVALID) {
249→        SYS_FS_ERROR err = SYS_FS_Error();
250→        LOG_E("[SD] ListFiles: Failed to open directory '%s', error=%d\r\n", dirPath, err);
251→        strBuffIndex += snprintf((char *) pStrBuff + strBuffIndex, strBuffSize - strBuffIndex,
252→                "\r\n[Error:%d]Failed to open directory [%s]\r\n", err, dirPath);
253→        if (strBuffIndex > 0 && sendChunk) {
254→            sendChunk(pStrBuff, strBuffIndex);
255→        }
256→        return;
257→    }
258→
259→    while (true) {
260→        if (SYS_FS_DirRead(dirHandle, &stat) == SYS_FS_RES_FAILURE) {
261→            SYS_FS_ERROR err = SYS_FS_Error();
262→            strBuffIndex += snprintf((char *) pStrBuff + strBuffIndex, strBuffSize - strBuffIndex,
263→                    "\r\n[Error:%d]Failed to read directory\r\n", err);
264→            break;
265→        }
266→
267→        if (stat.fname[0] == '\0') {
268→            LOG_D("[SD] ListFiles: End of directory\r\n");
269→            break;
270→        }
271→
272→        LOG_D("[SD] ListFiles: Read entry '%s'\r\n", stat.fname);
273→
274→        if (strcmp(stat.fname, ".") == 0 || strcmp(stat.fname, "..") == 0) {
275→            continue;
276→        }
277→
278→        snprintf(newPath, SD_CARD_MANAGER_FILE_PATH_LEN_MAX, "%s/%s", dirPath, stat.fname);
279→
280→        if (stat.fattrib & SYS_FS_ATTR_DIR) {
281→            // For subdirectories, recursively list (skip for now to keep simple)
282→            LOG_D("[SD] ListFiles: Skipping subdirectory '%s'\r\n", newPath);
283→        } else {
284→            LOG_D("[SD] ListFiles: Found file '%s'\r\n", newPath);
285→            int n = snprintf(NULL, 0, "%s\r\n", newPath);  // Calculate length needed
286→
287→            // Check if buffer is getting full - need space for this entry
288→            if (n > 0 && (strBuffIndex + n) >= (strBuffSize - 4)) {
289→                // Send current chunk before adding this entry
290→                if (sendChunk && strBuffIndex > 0) {
291→                    pStrBuff[strBuffIndex] = '\0';
292→                    sendChunk(pStrBuff, strBuffIndex);
293→                    strBuffIndex = 0;  // Reset buffer for next chunk
294→                }
295→            }
296→
297→            // Now add the filename and size to buffer (space-separated)
298→            n = snprintf((char *) pStrBuff + strBuffIndex, strBuffSize - strBuffIndex,
299→                    "%s %u\r\n", newPath, (unsigned)stat.fsize);
300→            if (n > 0 && (size_t)n < strBuffSize - strBuffIndex) {

300→            if (n > 0 && (size_t)n < strBuffSize - strBuffIndex) {
301→                strBuffIndex += (size_t)n;
302→            } else {
303→                // Entry doesn't fit - flush buffer and retry with fresh buffer
304→                if (sendChunk && strBuffIndex > 0) {
305→                    pStrBuff[strBuffIndex] = '\0';
306→                    sendChunk(pStrBuff, strBuffIndex);
307→                    strBuffIndex = 0;
308→
309→                    // Retry with fresh buffer
310→                    n = snprintf((char *) pStrBuff, strBuffSize,
311→                                "%s %u\r\n", newPath, (unsigned)stat.fsize);
312→                    if (n > 0 && (size_t)n < strBuffSize) {
313→                        strBuffIndex = (size_t)n;
314→                    }
315→                    // If still doesn't fit, entry is too large for buffer (skip it)
316→                }
317→            }
318→        }
319→    }
320→
321→    // Send final chunk if any data remains
322→    if (sendChunk && strBuffIndex > 0) {
323→        // Remove trailing CRLF from final chunk to avoid extra blank line before prompt
324→        while (strBuffIndex > 0 && (pStrBuff[strBuffIndex - 1] == '\r' || pStrBuff[strBuffIndex - 1] == '\n')) {
325→            strBuffIndex--;
326→        }
327→        if (strBuffIndex > 0) {
328→            pStrBuff[strBuffIndex] = '\0';
329→            sendChunk(pStrBuff, strBuffIndex);
330→        }
331→    }
332→
333→    SYS_FS_DirClose(dirHandle);
334→}
