336→bool sd_card_manager_Init(sd_card_manager_settings_t *pSettings) {
337→    static bool isInitDone = false;
338→    if (!isInitDone) {
339→        // Initialize circular buffer using static coherent memory instead of heap
340→        gSDCardData.wCirbuf.buf_ptr = gSdSharedBuffer;
341→        gSDCardData.wCirbuf.buf_size = SD_CARD_MANAGER_CIRCULAR_BUFFER_SIZE;
342→        gSDCardData.wCirbuf.process_callback = CircularBufferToSDWrite;
343→        gSDCardData.wCirbuf.insertPtr = gSdSharedBuffer;
344→        gSDCardData.wCirbuf.removePtr = gSdSharedBuffer;
345→        gSDCardData.wCirbuf.totalBytes = 0;
346→
347→        gSDCardData.wMutex = xSemaphoreCreateMutex();
348→        xSemaphoreGive(gSDCardData.wMutex);
349→        gSDCardData.opCompleteSemaphore = xSemaphoreCreateBinary();
350→        gSDCardData.lastOperationSuccess = true;  // Initialize to success
351→
352→        // Create operation mutex to serialize READ/WRITE/LIST on gSDSharedBuffer
353→        if (gSDOpMutex == NULL) {
354→            gSDOpMutex = xSemaphoreCreateMutex();
355→        }
356→        isInitDone = true;
357→        gpSDCardSettings = pSettings;
358→        gSDCardData.fileHandle = SYS_FS_HANDLE_INVALID;
359→        gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_INIT;
360→
361→        // Initialize file splitting state
362→        memset(gSDCardData.baseFilename, 0, sizeof(gSDCardData.baseFilename));
363→        gSDCardData.fileCounter = 0;
364→        gSDCardData.currentFileBytes = 0;
365→        gSDCardData.fileSplittingEnabled = false;
366→    }
367→    return true;
368→}
