370→/**
371→ * @brief Extracts base filename (without extension) from given filename.
372→ *
373→ * Example: "data.csv" → "data" stored in baseFilename field
374→ *
375→ * @param filename Input filename (may include extension)
376→ */
377→static void extractBaseFilename(const char* filename) {
378→    strncpy(gSDCardData.baseFilename, filename, sizeof(gSDCardData.baseFilename) - 1);
379→    gSDCardData.baseFilename[sizeof(gSDCardData.baseFilename) - 1] = '\0';
380→
381→    // Find last dot for extension
382→    char* ext = strrchr(gSDCardData.baseFilename, '.');
383→    if (ext != NULL) {
384→        *ext = '\0';  // Remove extension from base filename
385→    }
386→}
387→
388→/**
389→ * @brief Generates filename with sequential numbering.
390→ *
391→ * Format: basename-NNN.ext (e.g., "data-001.csv", "data-002.csv")
392→ *
393→ * @param outPath Output buffer for full path
394→ * @param maxLen Maximum length of output buffer
395→ * @param counter File counter (1, 2, 3, ...)
396→ * @param directory Directory path
397→ * @param baseFilename Base filename (without extension)
398→ * @param originalFilename Original filename (used to extract extension)
399→ */
400→static void generateFilename(char* outPath, size_t maxLen, uint32_t counter,
401→                             const char* directory, const char* baseFilename,
402→                             const char* originalFilename) {
403→    // Extract extension (includes leading dot if present)
404→    const char* ext = strrchr(originalFilename, '.');
405→    const char* useExt = (ext != NULL) ? ext : "";
406→
407→    // Pre-validate length to avoid truncation
408→    size_t dirLen = strlen(directory);
409→    size_t baseLen = strlen(baseFilename);
410→    size_t origLen = strlen(originalFilename);
411→    if (counter == 0) {
412→        if (dirLen + 1 + origLen + 1 > maxLen) {
413→            LOG_E("[%s:%d]Filename too long: dir='%s' file='%s' (max %zu)",
414→                  __FILE__, __LINE__, directory, originalFilename, maxLen);
415→            outPath[0] = '\0';
416→            return;
417→        }
418→    } else {
419→        if (dirLen + 1 + baseLen + 1 + 10 + strlen(useExt) + 1 > maxLen) {
420→            LOG_E("[%s:%d]Filename too long for split file: dir='%s' base='%s' ext='%s' (max %zu)",
421→                  __FILE__, __LINE__, directory, baseFilename, useExt, maxLen);
422→            outPath[0] = '\0';
423→            return;
424→        }
425→    }
426→
427→    int written;
428→    if (counter == 0) {
429→        written = snprintf(outPath, maxLen, "%s/%s", directory, originalFilename);
430→    } else {
431→        written = snprintf(outPath, maxLen, "%s/%s-%u%s", directory, baseFilename, counter, useExt);
432→    }
433→
434→    if (written < 0 || (size_t)written >= maxLen) {
435→        LOG_E("[%s:%d]Filename buffer overflow (needed %d bytes, have %zu): dir='%s' base='%s' cnt=%u ext='%s'",
436→              __FILE__, __LINE__, written, maxLen, directory, baseFilename, counter, useExt);
437→        outPath[0] = '\0';
438→    }
439→}
440→
441→void sd_card_manager_ProcessState() {
442→    /* Check the application's current state. */
443→
444→    switch (gSDCardData.currentProcessState) {
445→        case SD_CARD_MANAGER_PROCESS_STATE_INIT:
446→            // Only initialize if SD is enabled AND has a valid operation mode
447→            // Just enabling SD without setting a mode (WRITE/READ/LIST) is valid - don't spam errors
448→            if (gpSDCardSettings->enable && gpSDCardSettings->mode != SD_CARD_MANAGER_MODE_NONE) {
449→                // Validate directory and file settings
450→                bool dirValid = strlen(gpSDCardSettings->directory) > 0 &&
451→                               strlen(gpSDCardSettings->directory) <= SD_CARD_MANAGER_CONF_DIR_NAME_LEN_MAX;
452→                bool fileValid = strlen(gpSDCardSettings->file) > 0 &&
453→                                strlen(gpSDCardSettings->file) <= SD_CARD_MANAGER_CONF_FILE_NAME_LEN_MAX;
454→
455→                // LIST and FORMAT modes don't need a filename
456→                // DELETE, READ, WRITE need a filename
457→                bool needsFile = (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_DELETE_FILE ||
458→                                 gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_READ ||
459→                                 gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_WRITE);
460→
461→                // Reset error flag on valid configuration (allows new errors to be logged after fix)
462→                static bool errorLogged = false;
463→
464→                if (dirValid && (!needsFile || fileValid)) {
465→                    errorLogged = false;  // Reset flag on successful validation
466→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_MOUNT_DISK;
467→                } else {
468→                    // Only log error once per enable, not continuously
469→                    if (!errorLogged) {
470→                        LOG_E("[%s:%d]Invalid SD Card Directory or file name (dir='%s', file='%s')",
471→                              __FILE__, __LINE__,
472→                              gpSDCardSettings->directory,
473→                              gpSDCardSettings->file);
474→                        errorLogged = true;
475→                    }
476→                }
477→            }
478→            break;
479→        case SD_CARD_MANAGER_PROCESS_STATE_MOUNT_DISK:
480→            gSDCardData.sdCardWritePending = 0;
481→            gSDCardData.writeBufferLength = 0;
482→            gSDCardData.sdCardWriteBufferOffset = 0;
483→            {
484→                TickType_t mountStart = xTaskGetTickCount();
485→                int mountResult = SYS_FS_Mount(SD_CARD_MANAGER_DISK_DEV_NAME, SD_CARD_MANAGER_DISK_MOUNT_NAME, FAT, 0, NULL);
486→                SD_CheckFsOpDuration(mountStart, "SYS_FS_Mount", mountResult);
487→                if (mountResult != 0) {
488→                    /* The disk could not be mounted. Try
489→                     * mounting again until success. */
490→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_MOUNT_DISK;
491→                } else {
492→                    /* Mount was successful. Unmount the disk, for testing. */
493→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_CURRENT_DRIVE;
494→                    gSDCardData.discMounted = true;
495→                }
496→            }
497→            break;
498→
499→        case SD_CARD_MANAGER_PROCESS_STATE_UNMOUNT_DISK:
500→            if (gSDCardData.fileHandle != SYS_FS_HANDLE_INVALID) {
501→                // Flush any pending data before closing to prevent data loss
502→                SD_TakeMutexDebug(gSDCardData.wMutex, "unmount_pending_check");
503→                bool hasPendingData = gSDCardData.totalBytesFlushPending > 0;
504→                xSemaphoreGive(gSDCardData.wMutex);
505→
506→                if (hasPendingData) {
507→                    LOG_D("[SD] Flushing %d bytes before unmount\r\n", (int)gSDCardData.totalBytesFlushPending);
508→                    TickType_t syncStart = xTaskGetTickCount();
509→                    int syncResult = SYS_FS_FileSync(gSDCardData.fileHandle);
510→                    SD_CheckFsOpDuration(syncStart, "FileSync(unmount)", syncResult);
511→                    if (syncResult != -1) {
512→                        SD_TakeMutexDebug(gSDCardData.wMutex, "unmount_flush");
513→                        gSDCardData.totalBytesFlushPending = 0;
514→                        xSemaphoreGive(gSDCardData.wMutex);
515→                        LOG_D("[SD] Flushed pending data before unmount\r\n");
516→                    } else {
517→                        LOG_E("[%s:%d]Error flushing before unmount", __FILE__, __LINE__);
518→                    }
519→                }
520→
521→                LOG_D("[SD] Closing file '%s'\r\n", gSDCardData.filePath);
522→                SYS_FS_FileClose(gSDCardData.fileHandle);
523→                gSDCardData.fileHandle = SYS_FS_HANDLE_INVALID;
524→            }
525→            if (SYS_FS_Unmount(SD_CARD_MANAGER_DISK_MOUNT_NAME) == 0) {
526→                gSDCardData.discMounted = false;
527→                LOG_D("[SD] Unmounted successfully\r\n");
528→            }
529→            if (gSDCardData.discMounted == true) {
530→                /* The disk could not be un mounted. Try
531→                 * un mounting again untill success. */
532→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_UNMOUNT_DISK;
533→            } else {
534→                // Reset file splitting state for next session
535→                gSDCardData.fileCounter = 0;
536→                gSDCardData.currentFileBytes = 0;
537→                memset(gSDCardData.baseFilename, 0, sizeof(gSDCardData.baseFilename));
538→                gSDCardData.fileSplittingEnabled = false;
539→                LOG_D("[SD] File splitting state reset for next session\r\n");
540→
541→                // Always go back to INIT after unmounting
542→                // INIT will decide whether to mount based on enable flag and mode
543→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_INIT;
544→            }
545→            break;
546→
547→        case SD_CARD_MANAGER_PROCESS_STATE_CURRENT_DRIVE:
548→            if (SYS_FS_CurrentDriveSet(SD_CARD_MANAGER_DISK_MOUNT_NAME) == SYS_FS_RES_FAILURE) {
549→                /* Error while setting current drive */
550→                LOG_E("[%s:%d]Error Setting SD Card drive", __FILE__, __LINE__);
551→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_ERROR;
552→            } else {
553→                /* Open a file for reading. */
554→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_CREATE_DIRECTORY;
555→            }
556→            break;
557→
558→        case SD_CARD_MANAGER_PROCESS_STATE_CREATE_DIRECTORY:
559→            if (SYS_FS_DirectoryMake(gpSDCardSettings->directory) == SYS_FS_RES_FAILURE) {
560→                if (SYS_FS_Error() == SYS_FS_ERROR_EXIST) {
561→                    LOG_D("[SD] Directory '%s' already exists\r\n", gpSDCardSettings->directory);
562→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_OPEN_FILE;
563→                } else {
564→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_ERROR;
565→                    LOG_E("[%s:%d]Invalid SD Card Directory name '%s'", __FILE__, __LINE__, gpSDCardSettings->directory);
566→                }
567→                /* Error while creating a new drive */
568→            } else {
569→                LOG_D("[SD] Created directory '%s'\r\n", gpSDCardSettings->directory);
570→                /* Open a file for writing. */
571→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_OPEN_FILE;
572→            }
573→            break;
574→
575→        case SD_CARD_MANAGER_PROCESS_STATE_OPEN_FILE:
576→            memset(gSDCardData.filePath, 0, sizeof (gSDCardData.filePath));
577→            LOG_D("[SD] Opening file, mode=%d\r\n", gpSDCardSettings->mode);
578→            if (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_WRITE) {
579→                // Initialize file splitting if enabled
580→                gSDCardData.fileSplittingEnabled = (gpSDCardSettings->maxFileSizeBytes > 0);
581→
582→                // Extract base filename and generate actual filename with counter
583→                if (gSDCardData.fileCounter == 0) {
584→                    // First time opening - extract base filename
585→                    extractBaseFilename(gpSDCardSettings->file);
586→                }
587→
588→                generateFilename(gSDCardData.filePath, sizeof(gSDCardData.filePath),
589→                               gSDCardData.fileCounter, gpSDCardSettings->directory,
590→                               gSDCardData.baseFilename, gpSDCardSettings->file);
591→
592→                LOG_D("[SD] Opening file '%s' (counter=%u, splitting=%s)\r\n",
593→                     gSDCardData.filePath, gSDCardData.fileCounter,
594→                     gSDCardData.fileSplittingEnabled ? "enabled" : "disabled");
595→
596→                // Clear shared buffer and write buffer to prevent stale data from previous session
597→                SD_TakeMutexDebug(gSDCardData.wMutex, "open_file_clear_buffer");
598→                CircularBuf_Reset(&gSDCardData.wCirbuf);
599→                memset(gSdSharedBuffer, 0, SD_CARD_MANAGER_CIRCULAR_BUFFER_SIZE);

600→                memset(gSDCardData.writeBuffer, 0, sizeof(gSDCardData.writeBuffer));
601→                xSemaphoreGive(gSDCardData.wMutex);
602→
603→                // Use WRITE_PLUS to create/truncate file (overwrite mode)
604→                gSDCardData.fileHandle = SYS_FS_FileOpen(gSDCardData.filePath,
605→                        (SYS_FS_FILE_OPEN_WRITE_PLUS));
606→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_WRITE_TO_FILE;
607→                gSDCardData.totalBytesFlushPending = 0;
608→                gSDCardData.currentFileBytes = 0;  // Reset byte counter for new file
609→                gSDCardData.lastFlushMillis = pdTICKS_TO_MS(xTaskGetTickCount());
610→
611→                if (gSDCardData.fileHandle == SYS_FS_HANDLE_INVALID) {
612→                    /* Could not open the file. Error out*/
613→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_ERROR;
614→                    LOG_E("[%s:%d]Failed to open SD Card file for writing: '%s'", __FILE__, __LINE__, gSDCardData.filePath);
615→                }
616→            } else if (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_READ) {
617→                // For READ mode, construct filename directly from settings (no splitting)
618→                snprintf(gSDCardData.filePath, SD_CARD_MANAGER_FILE_PATH_LEN_MAX, "%s/%s",
619→                        gpSDCardSettings->directory, gpSDCardSettings->file);
620→                LOG_D("[SD] Opening file for read: '%s'\r\n", gSDCardData.filePath);
621→
622→                gSDCardData.fileHandle = SYS_FS_FileOpen(gSDCardData.filePath,
623→                        (SYS_FS_FILE_OPEN_READ));
624→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_READ_FROM_FILE;
625→
626→                if (gSDCardData.fileHandle == SYS_FS_HANDLE_INVALID) {
627→                    /* Could not open the file. Error out*/
628→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_ERROR;
629→                    LOG_E("[%s:%d]Failed to open SD Card file for reading: '%s'", __FILE__, __LINE__, gSDCardData.filePath);
630→                }
631→            } else if (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_LIST_DIRECTORY) {
632→                // LIST mode doesn't need to open a file, just list the directory
633→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_LIST_DIR;
634→            } else if (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_DELETE_FILE) {
635→                // DELETE mode - construct file path and delete the specified file
636→                // Initialize to false to prevent reading stale success from previous operation
637→                gSDCardData.lastOperationSuccess = false;
638→                // Strip trailing slash from directory to avoid double slashes
639→                size_t dirLen = strlen(gpSDCardSettings->directory);
640→                while (dirLen > 0 && gpSDCardSettings->directory[dirLen - 1] == '/') {
641→                    dirLen--;
642→                }
643→                int pathLen = snprintf(gSDCardData.filePath, SD_CARD_MANAGER_FILE_PATH_LEN_MAX, "%.*s/%s",
644→                        (int)dirLen, gpSDCardSettings->directory, gpSDCardSettings->file);
645→
646→                // Validate path was not truncated
647→                if (pathLen < 0 || pathLen >= (int)SD_CARD_MANAGER_FILE_PATH_LEN_MAX) {
648→                    LOG_E("[SD] Delete path too long (need %d, max %d)\r\n", pathLen, SD_CARD_MANAGER_FILE_PATH_LEN_MAX - 1);
649→                    gSDCardData.lastOperationSuccess = false;
650→                    gpSDCardSettings->mode = SD_CARD_MANAGER_MODE_NONE;
651→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_IDLE;
652→                    xSemaphoreGive(gSDCardData.opCompleteSemaphore);
653→                    break;
654→                }
655→
656→                // Reject path traversal attempts (e.g., "../" or "/..")
657→                if (strstr(gSDCardData.filePath, "..") != NULL) {
658→                    LOG_E("[SD] Delete path rejected (traversal attempt): '%s'\r\n", gSDCardData.filePath);
659→                    gSDCardData.lastOperationSuccess = false;
660→                    gpSDCardSettings->mode = SD_CARD_MANAGER_MODE_NONE;
661→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_IDLE;
662→                    xSemaphoreGive(gSDCardData.opCompleteSemaphore);
663→                    break;
664→                }
665→
666→                LOG_D("[SD] Preparing to delete file: '%s'\r\n", gSDCardData.filePath);
667→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_DELETE_FILE;
668→            } else if (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_FORMAT) {
669→                // FORMAT mode - erase all files on SD card
670→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_FORMAT;
671→            } else if (gpSDCardSettings->mode == SD_CARD_MANAGER_MODE_NONE) {
672→                gSDCardData.fileHandle = SYS_FS_FileOpen(gSDCardData.filePath,
673→                        (SYS_FS_FILE_OPEN_READ));
674→                gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_IDLE;
675→
676→                if (gSDCardData.fileHandle == SYS_FS_HANDLE_INVALID) {
677→                    /* Could not open the file. Error out*/
678→                    gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_ERROR;
679→                    LOG_E("[%s:%d]Failed to open SD Card file: '%s'", __FILE__, __LINE__, gSDCardData.filePath);
680→                }
681→            }
682→            break;
683→        case SD_CARD_MANAGER_PROCESS_STATE_WRITE_TO_FILE:
684→        {
685→            /* If read was success, try writing to the new file */
686→            int writeLen = -2;
687→            
688→            // Process multiple chunks per cycle for better throughput
689→            int chunksProcessed = 0;
690→            
691→            while (chunksProcessed < SD_CARD_MANAGER_MAX_CHUNKS_PER_CYCLE) {
692→                SD_TakeMutexDebug(gSDCardData.wMutex, "write_loop_check");
693→                if (CircularBuf_NumBytesAvailable(&gSDCardData.wCirbuf) > 0
694→                        && gSDCardData.sdCardWritePending != 1) {
695→                    gSDCardData.sdCardWritePending = 1;
696→                    CircularBuf_ProcessBytes(&gSDCardData.wCirbuf, NULL, SD_CARD_MANAGER_CONF_WBUFFER_SIZE, &writeLen);
697→                    gSDCardData.totalBytesFlushPending += gSDCardData.writeBufferLength;
698→                    xSemaphoreGive(gSDCardData.wMutex);
699→                    chunksProcessed++;
700→                } else {
701→                    // No data available or write already pending, release mutex
702→                    xSemaphoreGive(gSDCardData.wMutex);
703→                    
704→                    // Note: sdCardWritePending check outside mutex is safe here because:
705→                    // 1. Only this task modifies sdCardWritePending
706→                    // 2. We're coordinating work within a single task, not between tasks
707→                    // If this changes in future, this will need mutex protection
708→                    if (gSDCardData.sdCardWritePending == 1) {
709→                        writeLen = SDCardWrite();
710→                        if (writeLen >= gSDCardData.writeBufferLength) {
711→                            // Track bytes written for file splitting
712→                            gSDCardData.currentFileBytes += gSDCardData.writeBufferLength;
713→
714→                            SD_TakeMutexDebug(gSDCardData.wMutex, "write_complete");
715→                            gSDCardData.sdCardWritePending = 0;
716→                            gSDCardData.writeBufferLength = 0;
717→                            gSDCardData.sdCardWriteBufferOffset = 0;
718→                            xSemaphoreGive(gSDCardData.wMutex);
719→                        } else if (writeLen >= 0) {
720→                            // Track partial write
721→                            gSDCardData.currentFileBytes += writeLen;
722→
723→                            SD_TakeMutexDebug(gSDCardData.wMutex, "partial_write");
724→                            gSDCardData.writeBufferLength -= writeLen;
725→                            gSDCardData.sdCardWriteBufferOffset = writeLen;
726→                            xSemaphoreGive(gSDCardData.wMutex);
727→                            break;  // Partial write, don't process more chunks
728→                        } else if (writeLen == -1) {
729→                            gSDCardData.currentProcessState = SD_CARD_MANAGER_PROCESS_STATE_ERROR;
730→                            LOG_E("[%s:%d]Error Writing to SD Card", __FILE__, __LINE__);
731→                            break;
732→                        }
733→                    } else {
734→                        break;  // No more data to process
735→                    }
736→                }
737→            }
738→
739→            // Check if file size limit reached and rotation is needed
740→            if (gSDCardData.fileSplittingEnabled &&
741→                gSDCardData.currentFileBytes >= gpSDCardSettings->maxFileSizeBytes) {
742→                LOG_D("[SD] File size limit reached (%llu >= %llu), rotating to next file\r\n",
743→                     gSDCardData.currentFileBytes, gpSDCardSettings->maxFileSizeBytes);
744→
745→                // Drain circular buffer completely before rotation to prevent data loss
746→                SD_TakeMutexDebug(gSDCardData.wMutex, "drain_buffer_check");
747→                size_t bufferBytes = CircularBuf_NumBytesAvailable(&gSDCardData.wCirbuf);
748→                xSemaphoreGive(gSDCardData.wMutex);
749→
750→                if (bufferBytes > 0) {
751→                    LOG_D("[SD] Draining %zu bytes from circular buffer before rotation\r\n", bufferBytes);
752→                    // Process all remaining data in circular buffer
753→                    while (CircularBuf_NumBytesAvailable(&gSDCardData.wCirbuf) > 0) {
754→                        int writeLen = -2;
755→                        SD_TakeMutexDebug(gSDCardData.wMutex, "drain_loop");
756→                        if (gSDCardData.sdCardWritePending != 1) {
757→                            gSDCardData.sdCardWritePending = 1;
758→                            CircularBuf_ProcessBytes(&gSDCardData.wCirbuf, NULL, SD_CARD_MANAGER_CONF_WBUFFER_SIZE, &writeLen);
759→                            gSDCardData.totalBytesFlushPending += gSDCardData.writeBufferLength;
760→                            xSemaphoreGive(gSDCardData.wMutex);
761→
762→                            // Write immediately
763→                            writeLen = SDCardWrite();
764→                            if (writeLen >= 0) {
765→                                gSDCardData.currentFileBytes += writeLen;
766→                                SD_TakeMutexDebug(gSDCardData.wMutex, "drain_complete");
767→                                gSDCardData.sdCardWritePending = 0;
768→                                gSDCardData.writeBufferLength = 0;
769→                                gSDCardData.sdCardWriteBufferOffset = 0;
770→                                xSemaphoreGive(gSDCardData.wMutex);
771→                            } else {
772→                                LOG_E("[%s:%d]Error draining buffer before rotation", __FILE__, __LINE__);
773→                                break;
774→                            }
775→                        } else {
