1073→size_t sd_card_manager_WriteToBuffer(const char* pData, size_t len) {
1074→    size_t bytesAdded = 0;
1075→    if (len == 0)return 0;
1076→    if (gpSDCardSettings->enable != 1 || gpSDCardSettings->mode != SD_CARD_MANAGER_MODE_WRITE) {
1077→        return 0;
1078→    }
1079→    
1080→    // Wait for buffer space with mutex protection and timeout
1081→    bool hasSpace = false;
1082→    TickType_t startTime = xTaskGetTickCount();
1083→    TickType_t timeoutTicks = pdMS_TO_TICKS(SD_CARD_MANAGER_WRITE_TIMEOUT_MS);
1084→    
1085→    while (!hasSpace) {
1086→        // Check buffer space with mutex protection
1087→        SD_TakeMutexDebug(gSDCardData.wMutex, "write_buffer_space_check");
1088→        hasSpace = (CircularBuf_NumBytesFree(&gSDCardData.wCirbuf) >= len);
1089→        xSemaphoreGive(gSDCardData.wMutex);
1090→        
1091→        if (!hasSpace) {
1092→            // Check for timeout
1093→            if ((xTaskGetTickCount() - startTime) >= timeoutTicks) {
1094→                LOG_E("SD: WriteToBuffer timeout - buffer full for %u ms", SD_CARD_MANAGER_WRITE_TIMEOUT_MS);
1095→                return 0;
1096→            }
1097→            vTaskDelay(pdMS_TO_TICKS(SD_CARD_MANAGER_WRITE_WAIT_INTERVAL_MS));
1098→        }
1099→    }
1100→    
1101→    //Obtain ownership of the mutex object
1102→    SD_TakeMutexDebug(gSDCardData.wMutex, "write_buffer_add");
1103→    bytesAdded = CircularBuf_AddBytes(&gSDCardData.wCirbuf, (uint8_t*) pData, len);
1104→    xSemaphoreGive(gSDCardData.wMutex);
1105→
1106→    static uint32_t totalWritten = 0;
1107→    static uint32_t writeCount = 0;
1108→    totalWritten += bytesAdded;
1109→    writeCount++;
1110→    if (writeCount % 10 == 0) {  // Log every 10 writes to avoid spam
1111→        LOG_D("[SD] WriteToBuffer: %u writes, %u total bytes\r\n", writeCount, totalWritten);
1112→    }
1113→
1114→    return bytesAdded;
1115→}
