541→                message.has_analog_in_port_num = true;
542→                message.analog_in_port_num = 0;
543→
544→                if (pBoardConfig == NULL || pBoardConfig->AInChannels.Size == 0 || pBoardConfig->AInModules.Size == 0) {
545→                    break;
546→                }
547→
548→                for (uint32_t x = 0; x < pBoardConfig->AInChannels.Size; x++) {
549→                    if (AInChannel_IsPublic(&pBoardConfig->AInChannels.Data[x])) {
550→                        message.analog_in_port_num++;
551→                    }
552→                }
553→
554→                break;
555→            }
556→
557→            case DaqifiOutMessage_analog_in_port_num_priv_tag:
558→            {
559→                /**
560→                 * @brief Counts private analog input channels for the MC12bADC module.
561→                 *
562→                 * This tag counts the number of private (non-public) analog input channels
563→                 * in the `MC12bADC` module and stores the result in `analog_in_port_num_priv`.
564→                 * Only channels marked as private (`IsPublic == false`) are counted. Channels 
565→                 * from other module types are ignored.
566→                 */
567→                message.has_analog_in_port_num_priv = true;
568→                message.analog_in_port_num_priv = 0;
569→
570→                if (pBoardConfig == NULL || pBoardConfig->AInChannels.Size == 0 || pBoardConfig->AInModules.Size == 0) {
571→                    break;
572→                }
573→
574→                for (uint32_t x = 0; x < pBoardConfig->AInChannels.Size; x++) {
575→                    if (!AInChannel_IsPublic(&pBoardConfig->AInChannels.Data[x])) {
576→                        message.analog_in_port_num_priv++;
577→                    }
578→                }
579→
580→                break;
581→            }
582→            case DaqifiOutMessage_analog_in_port_type_tag:
583→                message.has_analog_in_port_type = false;
584→                break;
585→            case DaqifiOutMessage_analog_in_port_av_rse_tag:
586→                message.has_analog_in_port_av_rse = false;
587→                break;
588→            case DaqifiOutMessage_analog_in_port_rse_tag:
589→            {
590→                /**
591→                 * @brief Encodes the analog input channels as single-ended (RSE) or differential.
592→                 *
593→                 * Each bit in `analog_in_port_rse` represents whether the corresponding analog input
594→                 * channel is configured as differential or single-ended:
595→                 * - Bit 1 (set) = Differential
596→                 * - Bit 0 (clear) = Single-ended (RSE)
597→                 */
598→                uint32_t x = 0;
599→                uint32_t data = 0;
600→                message.has_analog_in_port_rse = true;
601→                for (x = 0; x < pBoardConfig->AInChannels.Size; x++) {
602→                    data |=
603→                            (pRuntimeAInChannels->Data[x].IsDifferential << x);
604→                }
605→                int2PBByteArray(
606→                        data,
607→                        (pb_bytes_array_t*) & message.analog_in_port_rse,
608→                        sizeof (message.analog_in_port_rse.bytes));
609→                break;
610→            }
611→            case DaqifiOutMessage_analog_in_port_enabled_tag:
612→            {
613→                /**
614→                 * @brief Encodes the enabled state of analog input channels.
615→                 *
616→                 * This tag sets a bit for each channel in `analog_in_port_enabled`, where
617→                 * each bit indicates whether the corresponding channel is enabled (1) or 
618→                 * disabled (0).
619→                 */
620→                uint32_t x = 0;
621→                uint32_t data = 0;
622→                message.has_analog_in_port_enabled = true;
623→                for (x = 0; x < pBoardConfig->AInChannels.Size; x++) {
624→                    data |=
625→                            (pRuntimeAInChannels->Data[x].IsEnabled << x);
626→                }
627→                int2PBByteArray(
628→                        data,
629→                        (pb_bytes_array_t*) & message.analog_in_port_enabled,
630→                        sizeof (message.analog_in_port_enabled.bytes));
631→                break;
632→            }
633→            case DaqifiOutMessage_analog_in_port_av_range_tag:
634→            {
635→                /**
636→                 * @brief Encodes the available range settings for analog input modules.
637→                 *
638→                 * This tag stores the supported voltage ranges for each analog input module,
639→                 * indicating the possible ranges a module can operate within (e.g., 0-5V, �10V).
640→                 */
641→                message.analog_in_port_av_range[0] =
642→                        pRuntimeAInModules->Data[AIn_MC12bADC].Range;
643→                message.analog_in_port_av_range_count = 1;
644→                message.analog_in_port_range_count = 0;
645→                break;
646→            }
647→
648→            case DaqifiOutMessage_analog_in_port_av_range_priv_tag:
649→                message.analog_in_port_av_range_priv_count = 0;
650→                break;
651→            case DaqifiOutMessage_analog_in_port_range_tag:
652→            {
653→                /**
654→                 * @brief Encodes the range values for public analog input channels.
655→                 *
656→                 * This tag stores the input voltage ranges for each public analog input channel in
657→                 * `analog_in_port_range`. Channels from the `AIn_MC12bADC` module are checked for 
658→                 * public status, while channels from other module types are automatically considered public.
659→                 */
660→                uint32_t chan = 0;
661→                const uint32_t max_range_count = sizeof (message.analog_in_port_range) / sizeof (message.analog_in_port_range[0]);
662→
663→                for (uint32_t x = 0; x < pBoardConfig->AInChannels.Size; x++) {
664→                    if (AInChannel_IsPublic(&pBoardConfig->AInChannels.Data[x]) && chan < max_range_count) {
665→                        // Get range from appropriate module
666→                        if (pBoardConfig->AInChannels.Data[x].Type == AIn_MC12bADC) {
667→                            message.analog_in_port_range[chan++] = pRuntimeAInModules->Data[AIn_MC12bADC].Range;
668→                        } else if (pBoardConfig->AInChannels.Data[x].Type == AIn_AD7609) {
669→                            message.analog_in_port_range[chan++] = pRuntimeAInModules->Data[AIn_AD7609].Range;
670→                        }
671→                    }
672→                }
673→
674→                message.analog_in_port_range_count = chan;
675→                break;
676→
677→            }
678→            case DaqifiOutMessage_analog_in_port_range_priv_tag:
679→            {
680→                /**
681→                 * @brief Encodes the current range settings for private analog input channels.
682→                 *
683→                 * This tag stores the actual, active range configuration for each private analog input channel,
684→                 * indicating the voltage range currently being used by private channels.
685→                 */
686→                uint32_t chan = 0;
687→                const uint32_t max_range_count = sizeof (message.analog_in_port_range_priv) / sizeof (message.analog_in_port_range_priv[0]);
688→
689→                for (uint32_t x = 0; x < pBoardConfig->AInChannels.Size; x++) {
690→                    if (!AInChannel_IsPublic(&pBoardConfig->AInChannels.Data[x]) && chan < max_range_count) {
691→                        // Get range from appropriate module
692→                        if (pBoardConfig->AInChannels.Data[x].Type == AIn_MC12bADC) {
693→                            message.analog_in_port_range_priv[chan++] = pRuntimeAInModules->Data[AIn_MC12bADC].Range;
694→                        } else if (pBoardConfig->AInChannels.Data[x].Type == AIn_AD7609) {
695→                            message.analog_in_port_range_priv[chan++] = pRuntimeAInModules->Data[AIn_AD7609].Range;
696→                        }
697→                    }
698→                }
