1499→static scpi_result_t SCPI_StartStreaming(scpi_t * context) {
1500→    int32_t freq;
1501→
1502→    StreamingRuntimeConfig * pRunTimeStreamConfig = BoardRunTimeConfig_Get(
1503→            BOARDRUNTIME_STREAMING_CONFIGURATION);
1504→    const tBoardConfig * pBoardConfig = BoardConfig_Get(
1505→            BOARDCONFIG_ALL_CONFIG, 0);
1506→    // Check power state first - streaming requires powered-up state
1507→    const tPowerData *pPowerState = BoardData_Get(BOARDDATA_POWER_DATA, 0);
1508→    if (pPowerState == NULL) {
1509→        LOG_E("Streaming command rejected: Power data unavailable");
1510→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1511→        return SCPI_RES_ERR;
1512→    }
1513→    if (pPowerState->powerState != POWERED_UP && pPowerState->powerState != POWERED_UP_EXT_DOWN) {
1514→        LOG_E("Streaming command rejected: Device must be powered up (SYST:POW:STAT 1)");
1515→        SCPI_ErrorPush(context, SCPI_ERROR_EXECUTION_ERROR);
1516→        return SCPI_RES_ERR;
1517→    }
1518→
1519→    volatile AInRuntimeArray * pRuntimeAInChannels = BoardRunTimeConfig_Get(BOARDRUNTIMECONFIG_AIN_CHANNELS);
1520→    volatile AInArray *pBoardConfigADC = BoardConfig_Get(BOARDCONFIG_AIN_CHANNELS, 0);
1521→
1522→    // Validate ADC runtime/config pointers
1523→    if (pRuntimeAInChannels == NULL || pBoardConfigADC == NULL) {
1524→        LOG_E("Streaming command rejected: ADC runtime/config unavailable");
1525→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1526→        return SCPI_RES_ERR;
1527→    }
1528→
1529→    // Defensive bound check to avoid mismatched arrays
1530→    if (pBoardConfigADC->Size > pRuntimeAInChannels->Size) {
1531→        LOG_E("Streaming command rejected: ADC config/runtime size mismatch (%u > %u)",
1532→              pBoardConfigADC->Size, pRuntimeAInChannels->Size);
1533→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1534→        return SCPI_RES_ERR;
1535→    }
1536→
1537→    // timer running frequency
1538→    uint32_t clkFreq = TimerApi_FrequencyGet(pBoardConfig->StreamingConfig.TimerIndex);
1539→
1540→    //int i;
1541→    uint16_t activeType1ChannelCount = 0;
1542→    bool hasActiveAD7609Channels __attribute__((unused)) = false;
1543→    int i;
1544→    bool hasEnabledChannels = false;
1545→
1546→    // Count active PUBLIC ADC channels and detect AD7609 usage
1547→    // Internal monitoring channels (IsPublic=false) don't count as user channels
1548→    // Use minimum of both array sizes to prevent out-of-bounds access
1549→    size_t adcCount = pBoardConfigADC->Size < pRuntimeAInChannels->Size ?
1550→                      pBoardConfigADC->Size : pRuntimeAInChannels->Size;
1551→    for (i = 0; i < (int)adcCount; i++) {
1552→        if (pRuntimeAInChannels->Data[i].IsEnabled == 1) {
1553→            // Check IsPublic based on channel type (it's in the union)
1554→            bool isPublic = false;
1555→            if (pBoardConfigADC->Data[i].Type == AIn_AD7609) {
1556→                isPublic = pBoardConfigADC->Data[i].Config.AD7609.IsPublic;
1557→                if (isPublic) {
1558→                    hasEnabledChannels = true;
1559→                    hasActiveAD7609Channels = true;
1560→                }
1561→            } else if (pBoardConfigADC->Data[i].Type == AIn_MC12bADC) {
1562→                isPublic = pBoardConfigADC->Data[i].Config.MC12b.IsPublic;
1563→                if (isPublic) {
1564→                    hasEnabledChannels = true;
1565→                    if (pBoardConfigADC->Data[i].Config.MC12b.ChannelType == 1) {
1566→                        activeType1ChannelCount++;
1567→                    }
1568→                }
1569→            }
1570→        }
1571→    }
1572→
1573→    // Check if DIO is globally enabled
1574→    bool *pDIOGlobalEnable = BoardRunTimeConfig_Get(BOARDRUNTIMECONFIG_DIO_GLOBAL_ENABLE);
1575→    if (pDIOGlobalEnable && *pDIOGlobalEnable) {
1576→        hasEnabledChannels = true;
1577→    }
1578→
1579→    if (!hasEnabledChannels) {
1580→        LOG_E("Streaming command rejected: No ADC or DIO channels enabled");
1581→        SCPI_ErrorPush(context, SCPI_ERROR_SETTINGS_CONFLICT);
1582→        return SCPI_RES_ERR;
1583→    }
1584→
1585→    if (SCPI_ParamInt32(context, &freq, FALSE)) {
1586→        // Frequency = 0 is valid and means "disable streaming"
1587→        // (In future may support per-channel frequency where 0 disables that channel)
1588→        if (freq == 0) {
1589→            pRunTimeStreamConfig->IsEnabled = false;
1590→            Streaming_UpdateState();
1591→            return SCPI_RES_OK;
1592→        }
1593→
1594→        // NQ3 Smart Frequency Management:
1595→        // When external AD7609 channels are active WITHOUT any Type 1 MC12bADC channels,
1596→        // force internal monitoring to 1Hz (since only monitoring channels would be streaming)
1597→        if (hasActiveAD7609Channels && activeType1ChannelCount == 0 && freq > 1) {
1598→            freq = 1; // Override to 1Hz for internal monitoring when external ADC active
1599→        }
1600→
1601→        // Maximum frequency limited to 15kHz pending optimization
1602→        // See https://github.com/daqifi/daqifi-nyquist-firmware/issues/58
1603→        if (freq >= 1 && freq <= 15000)
1604→        {
1605→            /**
1606→             * The maximum aggregate trigger frequency for all active Type 1 ADC channels is 15,000 Hz.
1607→             * For example, if two Type 1 channels are active, each can trigger at a maximum frequency of 7,500 Hz (15,000 / 2).
1608→             *
1609→             * The maximum triggering frequency of non type 1 channel is 1000 hz,
1610→             * which is obtained by dividing Frequency with ChannelScanFreqDiv.
1611→             * Non-Type 1 channels are setup for channel scanning
1612→             *
1613→             */
1614→            if (activeType1ChannelCount > 0) {
1615→                // Avoid overflow: compare without multiplying freq * activeType1ChannelCount
1616→                // Instead of: (freq * activeType1ChannelCount) > 15000
1617→                // Use: freq > (15000 / activeType1ChannelCount)
1618→                if (freq > (15000 / activeType1ChannelCount)) {
1619→                    freq = 15000 / activeType1ChannelCount;
1620→
1621→                    // Prevent divide-by-zero: if too many channels active, return error
1622→                    if (freq == 0) {
1623→                        SCPI_ErrorPush(context, SCPI_ERROR_ILLEGAL_PARAMETER_VALUE);
1624→                        return SCPI_RES_ERR;
1625→                    }
1626→                }
1627→            }
1628→
1629→            // Note: Internal monitoring channels have fixed 1Hz in NQ3 runtime config
1630→
1631→            pRunTimeStreamConfig->ClockPeriod = clkFreq / freq;
1632→            pRunTimeStreamConfig->Frequency = freq;
1633→            pRunTimeStreamConfig->TSClockPeriod = 0xFFFFFFFF;
1634→            if (freq > 1000) {
1635→                pRunTimeStreamConfig->ChannelScanFreqDiv = freq / 1000;
1636→            } else {
1637→                pRunTimeStreamConfig->ChannelScanFreqDiv = 1;
1638→            }
1639→        } else {
1640→            return SCPI_RES_ERR;
1641→        }
1642→    } else {
1643→        //No freq given just stream with the current value
1644→    }
1645→
1646→    // Auto-detect interface only if user hasn't explicitly set it via SYSTem:STReam:INTerface
1647→    // If current interface matches what auto-detection would choose, allow override
1648→    // If different, user explicitly set it (e.g., SD or All) so preserve their choice

  1→/*! @file csv_encoder.c
  2→ * @brief CSV encoder for streaming analog and digital samples.
  3→ *
  4→ * Encodes sample data into a human-readable CSV format optimized for:
  5→ * - Only outputs enabled channels (reduces file size dramatically)
  6→ * - Self-documenting header with device info and column names
  7→ * - Per-channel timestamps for accurate timing analysis
  8→ * - Calibrated millivolt values for immediate use
  9→ *
 10→ * Uses fast integer-to-string conversion to avoid snprintf overhead
 11→ * in the hot path (data rows). Header generation uses snprintf for
 12→ * simplicity since it runs only once per session.
 13→ */
 14→
 15→#include "../services/DaqifiPB/DaqifiOutMessage.pb.h"
 16→#include "state/data/BoardData.h"
 17→#include "state/board/BoardConfig.h"
 18→#include "state/runtime/BoardRuntimeConfig.h"
 19→#include "Util/StringFormatters.h"
 20→#include "Util/Logger.h"  // For LOG_E
 21→#include "encoder.h"
 22→#include "csv_encoder.h"
 23→#include "../HAL/ADC.h"
 24→#include "../HAL/TimerApi/TimerApi.h"
 25→#include <stdio.h>
 26→#include <stdint.h>
 27→#include <stdbool.h>
 28→#include <limits.h>  // For INT_MIN
 29→#include <string.h>  // For strlen
 30→
 31→// =============================================================================
 32→// Fast Integer Formatting (avoids snprintf overhead in hot path)
 33→// =============================================================================
 34→#define MAX_UINT32_STR_LEN 11  // Max digits for uint32_t (4294967295) + null
 35→
 36→/**
 37→ * @brief Converts uint32 to string without snprintf overhead.
 38→ *
 39→ * @param value  The value to convert
 40→ * @param buf    Output buffer pointer
 41→ * @param rem    Remaining space in buffer
 42→ * @return Updated buffer pointer, or NULL if insufficient space
 43→ */
 44→static inline char* uint32_to_str(uint32_t value, char* buf, size_t rem) {
 45→    if (rem == 0) {
 46→        return NULL;  // No space - signal error
 47→    }
 48→
 49→    if (value == 0) {
 50→        *buf++ = '0';
 51→        return buf;
 52→    }
 53→
 54→    char temp[MAX_UINT32_STR_LEN];
 55→    int len = 0;
 56→    while (value > 0) {
 57→        temp[len++] = '0' + (value % 10);
 58→        value /= 10;
 59→    }
 60→
 61→    // Check if we have enough space
 62→    if ((size_t)len > rem) {
 63→        return NULL;  // Not enough space - signal error
 64→    }
 65→
 66→    while (len > 0) {
 67→        *buf++ = temp[--len];
 68→    }
 69→
 70→    return buf;
 71→}
 72→
 73→/**
 74→ * @brief Converts signed int to string, handles INT_MIN edge case.
 75→ *
 76→ * @param value  The value to convert
 77→ * @param buf    Output buffer pointer
 78→ * @param rem    Remaining space in buffer
 79→ * @return Updated buffer pointer, or NULL if insufficient space
 80→ */
 81→static inline char* int_to_str(int value, char* buf, size_t rem) {
 82→    // Handle INT_MIN special case (-2147483648 cannot be negated safely)
