199→static size_t generateHeader(char *out, size_t rem, AInRuntimeArray* channelConfig, bool dioEnabled) {
200→    char *q = out;
201→
202→    // Get board config early with NULL check
203→    const tBoardConfig* boardConfig = (const tBoardConfig*)BoardConfig_Get(BOARDCONFIG_ALL_CONFIG, 0);
204→    if (!boardConfig) {
205→        LOG_E("[CSV] Board config is NULL, cannot generate header");
206→        return 0;  // Cannot generate header without board config
207→    }
208→
209→    // Get variant and serial number with NULL checks
210→    uint8_t variant = 0;
211→    uint64_t serialNum = 0;
212→    void* pVar = BoardConfig_Get(BOARDCONFIG_VARIANT, 0);
213→    void* pSer = BoardConfig_Get(BOARDCONFIG_SERIAL_NUMBER, 0);
214→    if (pVar) variant = *(uint8_t*)pVar;
215→    if (pSer) serialNum = *(uint64_t*)pSer;
216→
217→    if (rem < 2) return 0; // minimal safety
218→
219→    // Line 1: Device name
220→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_DEVICE_PREFIX);
221→    q = fast_strcpy_bounded(q, &rem, DAQIFI_PRODUCT_NAME);
222→    if (rem == 0) return 0;
223→    *q++ = ' '; rem--;
224→
225→    char* before = q;
226→    q = uint32_to_str(variant, q, rem);
227→    if (q == NULL) return 0;
228→    size_t written = q - before;
229→    if (written > rem) return 0;  // Safety check
230→    rem -= written;
