417→/**
418→ * @brief Main CSV encoder - encodes all available samples into buffer.
419→ *
420→ * Encodes analog and DIO samples into CSV format. On first call, outputs
421→ * a header with device metadata and column names. Subsequent calls output
422→ * data rows only.
423→ *
424→ * @param state     Board data state (for DIO samples)
425→ * @param fields    Unused (for API compatibility with other encoders)
426→ * @param pBuffer   Output buffer
427→ * @param buffSize  Size of output buffer
428→ * @return Bytes written (excluding null terminator)
429→ */
430→size_t csv_Encode(
431→    tBoardData*       state,
432→    NanopbFlagsArray* fields,
433→    uint8_t*          pBuffer,
434→    size_t            buffSize
435→) {
436→    // Need at least room for '\n' + '\0'
437→    if (!pBuffer || buffSize < 2) {
438→        return 0;
439→    }
440→
441→    // Get channel enable configuration
442→    AInRuntimeArray* channelConfig = BoardRunTimeConfig_Get(BOARDRUNTIMECONFIG_AIN_CHANNELS);
443→    if (!channelConfig) {
444→        return 0;
445→    }
446→
447→    // Get DIO enable state
448→    bool* pDioEnable = (bool*)BoardRunTimeConfig_Get(BOARDRUNTIMECONFIG_DIO_GLOBAL_ENABLE);
449→    bool dioEnabled = (pDioEnable && *pDioEnable);
450→
451→    char   *p     = (char*)pBuffer;
452→    size_t  rem   = buffSize - 1;  // reserve 1 byte up front for '\0'
453→    size_t  total = 0;
454→
455→    // Generate header on first call
456→    if (!csvHeaderSent) {
457→        size_t headerLen = generateHeader(p, rem, channelConfig, dioEnabled);
458→        if (headerLen == 0) {
459→            // Not enough space to write header; don't emit partial data
460→            *p = '\0';
461→            return 0;
462→        }
463→        p += headerLen;
464→        rem -= headerLen;
465→        total += headerLen;
466→        csvHeaderSent = true;
467→    }
468→
469→    while (1) {
470→        bool hadAIN, hadDIO;
471→        // attempt to write the next row in-place
472→        size_t rowLen = tryWriteRow(p, rem, state, channelConfig, dioEnabled, &hadAIN, &hadDIO);
473→        if (rowLen == 0 || rowLen > rem) {
474→            break;  // no data left or row won?t fit
475→        }
476→
477→        // now that it?s safely written, consume the queues:
478→        if (hadAIN) {
479→            AInPublicSampleList_t *tmp = NULL;
480→            AInSampleList_PopFront(&tmp);
481→            AInSampleList_FreeToPool(tmp);  // Use object pool instead of vPortFree
482→        }
483→        if (hadDIO) {
484→            DIOSample tmpD;
485→            DIOSampleList_PopFront(&state->DIOSamples, &tmpD);
486→        }
487→
488→    
489→        p     += rowLen;
490→        rem   -= rowLen;
491→        total += rowLen;
492→    }
493→
494→ 
495→    *p = '\0';
496→    return total;
497→}
