102→        NanopbFlagsArray* fields,
103→        uint8_t* pBuffer, size_t buffSize) {
104→    int tmpLen = 0;
105→    char* charBuffer = (char*) pBuffer;
106→    size_t startIndex = 0;
107→    size_t initialOffsetIndex = 0;
108→    size_t i = 0;
109→    bool encodeDIO = false;
110→    bool encodeADC = false;
111→
112→    if (pBuffer == NULL) {
113→        return 0; // Return 0 if buffer is NULL
114→    }
115→
116→    if (buffSize < 10) {
117→        return 0;  // Minimum buffer size check
118→    }
119→
120→    // Generate metadata header on first call (once per streaming session)
121→    if (!jsonHeaderSent) {
122→        size_t headerLen = generateJsonHeader(charBuffer, buffSize);
123→        if (headerLen == 0) {
124→            // Not enough space for header
125→            if (buffSize > 0) {
126→                charBuffer[0] = '\0';
127→            }
128→            return 0;
129→        }
130→        startIndex = headerLen;
131→        initialOffsetIndex = startIndex;
132→        jsonHeaderSent = true;
133→
134→        // If no room left to start an object, send header now and return
135→        if (buffSize - startIndex <= 3) {  // Need at least "{\n" (3 bytes)
136→            if (buffSize > 0) {
137→                size_t term = startIndex < buffSize ? startIndex : (buffSize - 1);
138→                charBuffer[term] = '\0';
139→            }
140→            return startIndex;  // Return header bytes (valid data)
141→        }
142→    }
143→
144→    // Start JSON sample object (write at current offset)
145→    int objWritten = snprintf(charBuffer + startIndex, buffSize - startIndex, "{\n");
146→    if (objWritten < 0 || objWritten >= (int)(buffSize - startIndex)) {
147→        // Could not start a new JSON object; return what we have (e.g., header)
