 65→/**
 66→ * @brief Deferred interrupt handler for sample collection.
 67→ *
 68→ * This task runs at high priority and is notified by the timer ISR.
 69→ * It collects the latest ADC and DIO samples into an object pool entry,
 70→ * then pushes the entry to the sample queue for the streaming task.
 71→ *
 72→ * Critical path optimizations:
 73→ * - Uses object pool allocation (O(1)) instead of heap
 74→ * - Uses critical section for atomic sample copy (prevents torn reads)
 75→ * - Triggers next ADC conversion immediately after sample collection
 76→ */
 77→void _Streaming_Deferred_Interrupt_Task(void) {
 78→    TickType_t xBlockTime = portMAX_DELAY;
 79→#if  !defined(TEST_STREAMING)
 80→    uint8_t i = 0;
 81→    tBoardData * pBoardData = BoardData_Get(
 82→            BOARDDATA_ALL_DATA,
 83→            0);
 84→    tBoardConfig * pBoardConfig = BoardConfig_Get(
 85→            BOARDCONFIG_ALL_CONFIG,
 86→            0);
 87→
 88→    StreamingRuntimeConfig * pRunTimeStreamConf = BoardRunTimeConfig_Get(
 89→            BOARDRUNTIME_STREAMING_CONFIGURATION);
 90→
 91→    AInModRuntimeArray * pRunTimeAInModules = BoardRunTimeConfig_Get(
 92→            BOARDRUNTIMECONFIG_AIN_MODULES);
 93→    AInRuntimeArray* pAiRunTimeChannelConfig = BoardRunTimeConfig_Get(BOARDRUNTIMECONFIG_AIN_CHANNELS);
 94→    
 95→    AInPublicSampleList_t *pPublicSampleList=NULL;
 96→    AInSample *pAiSample;
 97→
 98→    uint64_t ChannelScanFreqDivCount = 0;
 99→#endif
100→    while (1) {
101→        ulTaskNotifyTake(pdFALSE, xBlockTime);
102→
103→#if  !defined(TEST_STREAMING)
104→        if (pRunTimeStreamConf->IsEnabled) {
105→            // Use object pool instead of heap allocation (eliminates vPortFree overhead)
106→            // No heap check needed - pool uses pre-allocated static memory
107→            pPublicSampleList = AInSampleList_AllocateFromPool();
108→            if(pPublicSampleList==NULL) {
109→                LOG_E("Streaming: Sample pool exhausted\r\n");
110→                continue;
111→            }
112→            for (i = 0; i < pAiRunTimeChannelConfig->Size; i++) {
113→                if (pAiRunTimeChannelConfig->Data[i].IsEnabled == 1
114→                        && AInChannel_IsPublic(&pBoardConfig->AInChannels.Data[i])) {
115→                    pAiSample = BoardData_Get(BOARDDATA_AIN_LATEST, i);
116→                    // Null check to prevent crash
117→                    if (pAiSample != NULL) {
118→                        // Use channel ID from BoardConfig (authoritative source) instead of sample data
119→                        pPublicSampleList->sampleElement[i].Channel=pBoardConfig->AInChannels.Data[i].DaqifiAdcChannelId;
120→                        // Copy entire sample atomically to prevent torn reads
121→                        // Task-only context - use efficient critical section
122→                        taskENTER_CRITICAL();
123→                        pPublicSampleList->sampleElement[i].Timestamp=pAiSample->Timestamp;
124→                        pPublicSampleList->sampleElement[i].Value=pAiSample->Value;
125→                        taskEXIT_CRITICAL();
126→
127→                        pPublicSampleList->isSampleValid[i]=1;
128→                    } else {
129→                        // Mark as invalid if sample data unavailable
130→                        pPublicSampleList->isSampleValid[i]=0;
131→                    }
132→                }
133→            }
134→            if(!AInSampleList_PushBack(pPublicSampleList)){//failed pushing to Q
135→                static uint32_t queueDropCount = 0;
136→                if ((++queueDropCount % LOG_QUEUE_DROP_INTERVAL) == 0) {
137→                    LOG_E("Streaming: Sample queue full - dropped %u samples (queue at capacity)",
138→                          (unsigned)queueDropCount);
139→                }
140→                AInSampleList_FreeToPool(pPublicSampleList);  // Use pool!
141→            }
142→
143→            if (pRunTimeStreamConf->ChannelScanFreqDiv == 1) {
144→                for (i = 0; i < pRunTimeAInModules->Size; ++i) {
145→                    ADC_TriggerConversion(&pBoardConfig->AInModules.Data[i], MC12B_ADC_TYPE_ALL);
146→                }
147→            } else if (pRunTimeStreamConf->ChannelScanFreqDiv != 0) {
148→                for (i = 0; i < pRunTimeAInModules->Size; ++i) {
149→                    ADC_TriggerConversion(&pBoardConfig->AInModules.Data[i], MC12B_ADC_TYPE_DEDICATED);
150→                }
151→
152→                if (ChannelScanFreqDivCount >= pRunTimeStreamConf->ChannelScanFreqDiv) {
153→                    for (i = 0; i < pRunTimeAInModules->Size; ++i) {
154→                        ADC_TriggerConversion(&pBoardConfig->AInModules.Data[i], MC12B_ADC_TYPE_SHARED);
155→                    }
156→                    ChannelScanFreqDivCount = 0;
157→                }
158→                ChannelScanFreqDivCount++;
159→            }
160→            DIO_StreamingTrigger(&pBoardData->DIOLatest, &pBoardData->DIOSamples);
161→        }
162→       
163→        xTaskNotifyGive(gStreamingTaskHandle);
164→#else
165→        Streaming_StuffDummyData();
166→#endif
167→
168→    }
169→}
