  1→/*! @file csv_encoder.c
  2→ * @brief CSV encoder for streaming analog and digital samples.
  3→ *
  4→ * Encodes sample data into a human-readable CSV format optimized for:
  5→ * - Only outputs enabled channels (reduces file size dramatically)
  6→ * - Self-documenting header with device info and column names
  7→ * - Per-channel timestamps for accurate timing analysis
  8→ * - Calibrated millivolt values for immediate use
  9→ *
 10→ * Uses fast integer-to-string conversion to avoid snprintf overhead
 11→ * in the hot path (data rows). Header generation uses snprintf for
 12→ * simplicity since it runs only once per session.
 13→ */
 14→
 15→#include "../services/DaqifiPB/DaqifiOutMessage.pb.h"
 16→#include "state/data/BoardData.h"
 17→#include "state/board/BoardConfig.h"
 18→#include "state/runtime/BoardRuntimeConfig.h"
 19→#include "Util/StringFormatters.h"
 20→#include "Util/Logger.h"  // For LOG_E
 21→#include "encoder.h"
 22→#include "csv_encoder.h"
 23→#include "../HAL/ADC.h"
 24→#include "../HAL/TimerApi/TimerApi.h"
 25→#include <stdio.h>
 26→#include <stdint.h>
 27→#include <stdbool.h>
 28→#include <limits.h>  // For INT_MIN
 29→#include <string.h>  // For strlen
 30→
 31→// =============================================================================
 32→// Fast Integer Formatting (avoids snprintf overhead in hot path)
 33→// =============================================================================
 34→#define MAX_UINT32_STR_LEN 11  // Max digits for uint32_t (4294967295) + null
 35→
 36→/**
 37→ * @brief Converts uint32 to string without snprintf overhead.
 38→ *
 39→ * @param value  The value to convert
 40→ * @param buf    Output buffer pointer
 41→ * @param rem    Remaining space in buffer
 42→ * @return Updated buffer pointer, or NULL if insufficient space
 43→ */
 44→static inline char* uint32_to_str(uint32_t value, char* buf, size_t rem) {
 45→    if (rem == 0) {
 46→        return NULL;  // No space - signal error
 47→    }
 48→
 49→    if (value == 0) {
 50→        *buf++ = '0';
 51→        return buf;
 52→    }
 53→
 54→    char temp[MAX_UINT32_STR_LEN];
 55→    int len = 0;
 56→    while (value > 0) {
 57→        temp[len++] = '0' + (value % 10);
 58→        value /= 10;
 59→    }
 60→
 61→    // Check if we have enough space
 62→    if ((size_t)len > rem) {
 63→        return NULL;  // Not enough space - signal error
 64→    }
 65→
 66→    while (len > 0) {
 67→        *buf++ = temp[--len];
 68→    }
 69→
 70→    return buf;
 71→}
 72→
 73→/**
 74→ * @brief Converts signed int to string, handles INT_MIN edge case.
 75→ *
 76→ * @param value  The value to convert
 77→ * @param buf    Output buffer pointer
 78→ * @param rem    Remaining space in buffer
 79→ * @return Updated buffer pointer, or NULL if insufficient space
 80→ */
 81→static inline char* int_to_str(int value, char* buf, size_t rem) {
 82→    // Handle INT_MIN special case (-2147483648 cannot be negated safely)
 83→    if (value == INT_MIN) {
 84→        const char* str = "-2147483648";
 85→        size_t len = strlen(str);  // Calculate length programmatically
 86→        if (len > rem) {
 87→            return NULL;  // Not enough space - signal error
 88→        }
 89→        while (*str) {
 90→            *buf++ = *str++;
 91→        }
 92→        return buf;
 93→    }
 94→
 95→    if (value < 0) {
 96→        if (rem == 0) {
 97→            return NULL;  // No space for minus sign - signal error
 98→        }
 99→        *buf++ = '-';
100→        rem--;
101→        value = -value;
102→    }
103→    return uint32_to_str((uint32_t)value, buf, rem);  // Can return NULL
104→}
105→
106→// Track whether CSV header has been sent (reset when streaming stops)
107→static bool csvHeaderSent = false;
108→
109→// =============================================================================
110→// Pre-computed CSV Header Strings (stored in program memory for fast access)
111→// =============================================================================
112→// Avoids snprintf overhead during header generation - critical for minimizing
113→// file rotation pause at high sample rates (15kHz+).
114→
115→// Metadata header prefixes
116→static const char CSV_HEADER_DEVICE_PREFIX[] = "# Device: ";
117→static const char CSV_HEADER_TICKRATE_PREFIX[] = "# Timestamp Tick Rate: ";
118→static const char CSV_HEADER_HZ_SUFFIX[] = " Hz\n";
119→
120→// Channel header strings are now stored in board config (csvChannelHeadersFirst/Subsequent)
121→// This allows board-specific naming conventions (e.g., "ain" vs "ch" prefix)
122→
123→// DIO header strings
124→static const char CSV_DIO_HEADER_FIRST[] = "dio_ts,dio_val\n";
125→static const char CSV_DIO_HEADER_SUBSEQUENT[] = ",dio_ts,dio_val\n";
126→
127→/**
128→ * @brief Fast string copy from flash to RAM (inline for zero call overhead).
129→ *
130→ * Optimized for copying static strings from program memory. Avoids strlen()
131→ * overhead by copying until null terminator.
132→ *
133→ * @param dst Destination pointer
134→ * @param src Source string (typically from flash)
135→ * @return Updated destination pointer
136→ */
137→static inline char* fast_strcpy(char* dst, const char* src) {
138→    while (*src) {
139→        *dst++ = *src++;
140→    }
141→    return dst;
142→}
143→
144→static inline char* fast_strcpy_bounded(char* dst, size_t* prem, const char* src) {
145→    while (*src && *prem > 0) {
146→        *dst++ = *src++;
147→        (*prem)--;
148→    }
149→    return dst;
150→}
151→
152→/*
153→ * CSV Format (optimized - header with metadata + enabled channels only):
154→ *
155→ * Header (sent once per session):
156→ * # Device: Nyquist NQ1
157→ * # Sample Rate: 100 Hz
158→ * ch0_ts,ch0_val,ch4_ts,ch4_val,ch7_ts,ch7_val,dio_ts,dio_val
159→ *
160→ * Data rows (only enabled channels):
161→ * 798519461,2773,798519465,2801,798519469,2795,798520000,15
162→ *
163→ * Benefits:
164→ * - Only outputs enabled channels (not all 16)
165→ * - Self-documenting with device info and sample rate
166→ * - Column names identify channel mapping
167→ * - Dramatically smaller files (e.g., 1 channel = 4 fields vs 34 fields)
168→ * - Per-channel timestamps for accuracy
169→ *
170→ * Examples:
171→ *
172→ * 1. Single channel (ch4) enabled at 100Hz:
173→ *    # Device: Nyquist NQ1
174→ *    # Sample Rate: 100 Hz
175→ *    ch4_ts,ch4_val,dio_ts,dio_val
176→ *    798519461,2773,,
177→ *
178→ * 2. Multiple channels (ch0,4,7) at 5000Hz:
179→ *    # Device: Nyquist NQ1
180→ *    # Sample Rate: 5000 Hz
181→ *    ch0_ts,ch0_val,ch4_ts,ch4_val,ch7_ts,ch7_val,dio_ts,dio_val
182→ *    798519461,2773,798519465,2801,798519469,2795,798520000,15
183→ *
184→ */
185→
186→/**
187→ * @brief Reset CSV encoder state (call when streaming stops)
188→ */
189→void csv_ResetEncoder(void) {
190→    csvHeaderSent = false;
191→}
192→
193→/**
194→ * @brief Generate CSV header with device metadata and column names (optimized)
195→ *
196→ * Uses pre-computed strings from flash to minimize file rotation latency.
197→ * Critical for maintaining data continuity at high sample rates (15kHz+).
198→ */
199→static size_t generateHeader(char *out, size_t rem, AInRuntimeArray* channelConfig, bool dioEnabled) {
200→    char *q = out;
201→
202→    // Get board config early with NULL check
203→    const tBoardConfig* boardConfig = (const tBoardConfig*)BoardConfig_Get(BOARDCONFIG_ALL_CONFIG, 0);
204→    if (!boardConfig) {
205→        LOG_E("[CSV] Board config is NULL, cannot generate header");
206→        return 0;  // Cannot generate header without board config
207→    }
208→
209→    // Get variant and serial number with NULL checks
210→    uint8_t variant = 0;
211→    uint64_t serialNum = 0;
212→    void* pVar = BoardConfig_Get(BOARDCONFIG_VARIANT, 0);
213→    void* pSer = BoardConfig_Get(BOARDCONFIG_SERIAL_NUMBER, 0);
214→    if (pVar) variant = *(uint8_t*)pVar;
215→    if (pSer) serialNum = *(uint64_t*)pSer;
216→
217→    if (rem < 2) return 0; // minimal safety
218→
219→    // Line 1: Device name
220→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_DEVICE_PREFIX);
221→    q = fast_strcpy_bounded(q, &rem, DAQIFI_PRODUCT_NAME);
222→    if (rem == 0) return 0;
223→    *q++ = ' '; rem--;
224→
225→    char* before = q;
226→    q = uint32_to_str(variant, q, rem);
227→    if (q == NULL) return 0;
228→    size_t written = q - before;
229→    if (written > rem) return 0;  // Safety check
230→    rem -= written;
231→
232→    if (rem == 0) return 0;
233→    *q++ = '\n'; rem--;
234→
235→    // Line 2: Serial number
236→    int w = snprintf(q, rem, "# Serial Number: %016llX\n", (unsigned long long)serialNum);
237→    if (w < 0 || (size_t)w >= rem) return 0;
238→    q += w; rem -= (size_t)w;
239→
240→    // Line 3: Timestamp tick rate
241→    uint32_t tickRate = TimerApi_FrequencyGet(boardConfig->StreamingConfig.TSTimerIndex);
242→
243→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_TICKRATE_PREFIX);
244→
245→    before = q;
246→    q = uint32_to_str(tickRate, q, rem);
247→    if (q == NULL) return 0;
248→    written = q - before;
249→    if (written > rem) return 0;  // Safety check
250→    rem -= written;
251→
252→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_HZ_SUFFIX);
253→
254→    // Line 4: Column headers
255→    const char* const* headerFirst = boardConfig->csvChannelHeadersFirst;
256→    const char* const* headerSubsequent = boardConfig->csvChannelHeadersSubsequent;
257→    if (!headerFirst || !headerSubsequent) {
258→        LOG_E("[CSV] Board config missing CSV column header arrays");
259→        return 0;  // Safety check - arrays must be initialized
260→    }
261→
262→    bool firstCol = true;
263→    for (int i = 0; i < MAX_AIN_PUBLIC_CHANNELS; i++) {
264→        if (channelConfig->Data[i].IsEnabled) {
265→            const char* header = firstCol ? headerFirst[i] : headerSubsequent[i];
266→            q = fast_strcpy_bounded(q, &rem, header);
267→            firstCol = false;
268→        }
269→    }
270→
271→    if (dioEnabled) {
272→        const char* dio_header = firstCol ? CSV_DIO_HEADER_FIRST
273→                                          : CSV_DIO_HEADER_SUBSEQUENT;
274→        q = fast_strcpy_bounded(q, &rem, dio_header);
275→    } else {
276→        if (rem == 0) return 0;
277→        *q++ = '\n'; rem--;
278→    }
279→
280→    return (size_t)(q - out);
281→}
282→/**
283→ * @brief Attempts to write one data row to the output buffer.
284→ *
285→ * Writes timestamp,value pairs for all enabled analog channels and DIO.
286→ * Uses peek-before-pop strategy: peeks queues first to check data availability,
287→ * writes the row, then caller pops if successful.
288→ *
289→ * @param out           Output buffer
290→ * @param rem           Remaining space in buffer
