423→                    if (written < 0 || written >= (int)(buffSize - startIndex)) break;
424→                    startIndex += written;
425→                    timestampAdded = true;
426→                }
427→
428→
429→                double voltage = ADC_ConvertToVoltage(&data) * 1000; // Convert to millivolts
430→                int written = snprintf(charBuffer + startIndex,
431→                        buffSize - startIndex,
432→                        "{\"ch\":%u, \"val\":%u},\n",
