435→                if (written < 0 || written >= (int)(buffSize - startIndex)) break;
436→                startIndex += written;
437→            }
438→
439→            AInSampleList_FreeToPool(pPublicSampleList);  // Use pool instead of vPortFree
440→            if(startIndex == initialOffsetIndex) //no adc data added
441→                break;
442→            // Remove trailing comma and close adc array
443→            if (startIndex >= 2 && charBuffer[startIndex - 2] == ',') {
444→                startIndex -= 2; // Remove trailing comma
445→            }
446→            int written = snprintf(charBuffer + startIndex,
447→                    buffSize - startIndex,
448→                    "\n],\n");
449→            if (written < 0 || written >= (int)(buffSize - startIndex)) break;
450→            startIndex += written;
451→        }
452→    }
453→
454→    // Close the JSON object
455→    if (startIndex >= 2 && charBuffer[startIndex - 2] == ',') {
456→        startIndex -= 2; // Remove trailing comma
457→    }
458→    int written = snprintf(charBuffer + startIndex,
459→            buffSize - startIndex,
460→            "\n}\n");
461→    if (written < 0 || written >= (int)(buffSize - startIndex)) {
462→        // Truncated or error; incomplete JSON is invalid, signal failure
463→        if (buffSize > 0) {
464→            size_t term = (startIndex < buffSize) ? startIndex : (buffSize - 1);
465→            charBuffer[term] = '\0';
466→        }
467→        return 0;  // Invalid/incomplete JSON - return failure
468→    }
469→    startIndex += written;
470→
471→    // Ensure safe null-termination without exceeding buffer
472→    if (buffSize > 0) {
473→        charBuffer[startIndex < buffSize ? startIndex : (buffSize - 1)] = '\0';
474→    }
475→    return startIndex; // Return the number of bytes written
