476→static void Streaming_StuffDummyData(void) {
477→    // Stuff stream with some data
478→    // Copy dummy samples to the data list
479→    uint32_t i = 0;
480→    int k = 0;
481→    static AInSample data;
482→
483→    AInSampleList * pAInSamples = BoardData_Get(
484→            BOARDDATA_AIN_SAMPLES,
485→            0);
486→    StreamingRuntimeConfig * pRunTimeStreamConf = BoardRunTimeConfig_Get(
487→            BOARDRUNTIME_STREAMING_CONFIGURATION);
488→
489→    AInModRuntimeArray * pRunTimeAInModules = BoardRunTimeConfig_Get(
490→            BOARDRUNTIMECONFIG_AIN_MODULES);
491→
492→    AInRuntimeArray* pAiRunTimeChannelConfig = BoardRunTimeConfig_Get(BOARDRUNTIMECONFIG_AIN_CHANNELS);
493→
494→    AInArray * pBoardConfig = BoardConfig_Get(
495→            BOARDCONFIG_AIN_CHANNELS,
496→            0);
497→
498→    if (!pRunTimeStreamConf->IsEnabled) {
499→        return;
500→    }
501→    data.Timestamp++;
