152→/*
153→ * CSV Format (optimized - header with metadata + enabled channels only):
154→ *
155→ * Header (sent once per session):
156→ * # Device: Nyquist NQ1
157→ * # Sample Rate: 100 Hz
158→ * ch0_ts,ch0_val,ch4_ts,ch4_val,ch7_ts,ch7_val,dio_ts,dio_val
159→ *
160→ * Data rows (only enabled channels):
161→ * 798519461,2773,798519465,2801,798519469,2795,798520000,15
162→ *
163→ * Benefits:
164→ * - Only outputs enabled channels (not all 16)
165→ * - Self-documenting with device info and sample rate
166→ * - Column names identify channel mapping
167→ * - Dramatically smaller files (e.g., 1 channel = 4 fields vs 34 fields)
168→ * - Per-channel timestamps for accuracy
169→ *
170→ * Examples:
171→ *
172→ * 1. Single channel (ch4) enabled at 100Hz:
173→ *    # Device: Nyquist NQ1
174→ *    # Sample Rate: 100 Hz
175→ *    ch4_ts,ch4_val,dio_ts,dio_val
176→ *    798519461,2773,,
177→ *
178→ * 2. Multiple channels (ch0,4,7) at 5000Hz:
179→ *    # Device: Nyquist NQ1
180→ *    # Sample Rate: 5000 Hz
181→ *    ch0_ts,ch0_val,ch4_ts,ch4_val,ch7_ts,ch7_val,dio_ts,dio_val
182→ *    798519461,2773,798519465,2801,798519469,2795,798520000,15
183→ *
184→ */
185→
186→/**
187→ * @brief Reset CSV encoder state (call when streaming stops)
188→ */
189→void csv_ResetEncoder(void) {
190→    csvHeaderSent = false;
191→}
192→
193→/**
194→ * @brief Generate CSV header with device metadata and column names (optimized)
195→ *
196→ * Uses pre-computed strings from flash to minimize file rotation latency.
197→ * Critical for maintaining data continuity at high sample rates (15kHz+).
198→ */
199→static size_t generateHeader(char *out, size_t rem, AInRuntimeArray* channelConfig, bool dioEnabled) {
200→    char *q = out;
201→
202→    // Get board config early with NULL check
203→    const tBoardConfig* boardConfig = (const tBoardConfig*)BoardConfig_Get(BOARDCONFIG_ALL_CONFIG, 0);
204→    if (!boardConfig) {
205→        LOG_E("[CSV] Board config is NULL, cannot generate header");
206→        return 0;  // Cannot generate header without board config
207→    }
208→
209→    // Get variant and serial number with NULL checks
210→    uint8_t variant = 0;
211→    uint64_t serialNum = 0;
212→    void* pVar = BoardConfig_Get(BOARDCONFIG_VARIANT, 0);
213→    void* pSer = BoardConfig_Get(BOARDCONFIG_SERIAL_NUMBER, 0);
214→    if (pVar) variant = *(uint8_t*)pVar;
215→    if (pSer) serialNum = *(uint64_t*)pSer;
216→
217→    if (rem < 2) return 0; // minimal safety
218→
219→    // Line 1: Device name
220→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_DEVICE_PREFIX);
221→    q = fast_strcpy_bounded(q, &rem, DAQIFI_PRODUCT_NAME);
222→    if (rem == 0) return 0;
223→    *q++ = ' '; rem--;
224→
225→    char* before = q;
226→    q = uint32_to_str(variant, q, rem);
227→    if (q == NULL) return 0;
228→    size_t written = q - before;
229→    if (written > rem) return 0;  // Safety check
230→    rem -= written;
231→
232→    if (rem == 0) return 0;
233→    *q++ = '\n'; rem--;
234→
235→    // Line 2: Serial number
236→    int w = snprintf(q, rem, "# Serial Number: %016llX\n", (unsigned long long)serialNum);
237→    if (w < 0 || (size_t)w >= rem) return 0;
238→    q += w; rem -= (size_t)w;
239→
240→    // Line 3: Timestamp tick rate
241→    uint32_t tickRate = TimerApi_FrequencyGet(boardConfig->StreamingConfig.TSTimerIndex);
242→
243→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_TICKRATE_PREFIX);
244→
245→    before = q;
246→    q = uint32_to_str(tickRate, q, rem);
247→    if (q == NULL) return 0;
248→    written = q - before;
249→    if (written > rem) return 0;  // Safety check
250→    rem -= written;
251→
252→    q = fast_strcpy_bounded(q, &rem, CSV_HEADER_HZ_SUFFIX);
253→
254→    // Line 4: Column headers
255→    const char* const* headerFirst = boardConfig->csvChannelHeadersFirst;
256→    const char* const* headerSubsequent = boardConfig->csvChannelHeadersSubsequent;
257→    if (!headerFirst || !headerSubsequent) {
258→        LOG_E("[CSV] Board config missing CSV column header arrays");
259→        return 0;  // Safety check - arrays must be initialized
260→    }
261→
262→    bool firstCol = true;
263→    for (int i = 0; i < MAX_AIN_PUBLIC_CHANNELS; i++) {
264→        if (channelConfig->Data[i].IsEnabled) {
265→            const char* header = firstCol ? headerFirst[i] : headerSubsequent[i];
266→            q = fast_strcpy_bounded(q, &rem, header);
267→            firstCol = false;
268→        }
269→    }
270→
271→    if (dioEnabled) {
272→        const char* dio_header = firstCol ? CSV_DIO_HEADER_FIRST
273→                                          : CSV_DIO_HEADER_SUBSEQUENT;
274→        q = fast_strcpy_bounded(q, &rem, dio_header);
275→    } else {
276→        if (rem == 0) return 0;
277→        *q++ = '\n'; rem--;
278→    }
279→
280→    return (size_t)(q - out);
281→}
282→/**
283→ * @brief Attempts to write one data row to the output buffer.
284→ *
285→ * Writes timestamp,value pairs for all enabled analog channels and DIO.
286→ * Uses peek-before-pop strategy: peeks queues first to check data availability,
287→ * writes the row, then caller pops if successful.
288→ *
289→ * @param out           Output buffer
290→ * @param rem           Remaining space in buffer
291→ * @param state         Board data state (for DIO samples)
292→ * @param channelConfig Channel enable configuration
293→ * @param dioEnabled    Whether DIO output is enabled
294→ * @param hadAIN        [out] True if analog samples were available
295→ * @param hadDIO        [out] True if DIO samples were available
296→ * @return Bytes written (0 if no data or insufficient space)
297→ */
298→static size_t tryWriteRow(
299→    char       *out,
300→    size_t      rem,
301→    tBoardData *state,
302→    AInRuntimeArray* channelConfig,
303→    bool        dioEnabled,
304→    bool       *hadAIN,
305→    bool       *hadDIO
306→) {
307→    // 1) peek queues
308→    AInPublicSampleList_t *ainPeek = NULL;
309→    *hadAIN = AInSampleList_PeekFront(&ainPeek);
310→
311→    DIOSample dioPeek = {0};
312→    *hadDIO = DIOSampleList_PeekFront(&state->DIOSamples, &dioPeek);
313→
314→    
315→    if (!*hadAIN && !*hadDIO) {
316→        return 0;
317→    }
318→
319→    char *q = out;
320→    int   w;
321→    bool firstField = true;
322→
323→    // Write channel timestamp,value pairs (ONLY for enabled channels)
324→    for (int i = 0; i < MAX_AIN_PUBLIC_CHANNELS; i++) {
325→        // Skip disabled channels entirely
326→        if (!channelConfig->Data[i].IsEnabled) {
327→            continue;
328→        }
329→
330→        if (*hadAIN && ainPeek && ainPeek->isSampleValid[i]) {
331→            AInSample *s = &ainPeek->sampleElement[i];
332→
333→            // Convert to calibrated millivolts (backwards compatible)
334→            double voltage_mv = ADC_ConvertToVoltage(s) * 1000.0;
335→            // Clamp to int32_t range for portability
336→            int32_t mv;
337→            if (voltage_mv > (double)INT32_MAX) {
338→                mv = INT32_MAX;
339→            } else if (voltage_mv < (double)INT32_MIN) {
340→                mv = INT32_MIN;
341→            } else {
342→                // Round to nearest instead of truncation
343→                mv = (int32_t)(voltage_mv >= 0.0 ? voltage_mv + 0.5 : voltage_mv - 0.5);
344→            }
345→            // First field has no leading comma
346→            char* p = q;
347→            size_t space = rem;
348→            if (!firstField) {
349→                if (space == 0) return 0;  // Buffer exhausted
350→                *p++ = ',';
351→                space--;
352→            }
353→            p = uint32_to_str(s->Timestamp, p, space);
354→            if (p == NULL) return 0;  // Buffer exhausted
355→            size_t used = p - q;
356→            space = (used < rem) ? rem - used : 0;
357→            if (space == 0) return 0;  // Buffer exhausted
358→            *p++ = ',';
359→            space--;
360→            p = int_to_str(mv, p, space);
361→            if (p == NULL) return 0;  // Buffer exhausted
362→            w = p - q;
363→            firstField = false;
364→        } else {
365→            // No valid sample for this enabled channel: emit empty ts,val pair
366→            // Always two fields (timestamp and value) to align with header
367→            char* p = q;
368→            size_t space = rem;
369→
370→            // Check space before each write
371→            if (!firstField) {
372→                if (space == 0) return 0;  // Buffer exhausted
373→                *p++ = ',';  // separator before empty ts
374→                space--;
375→            }
376→            if (space < 1) return 0;  // Buffer exhausted
377→            *p++ = ',';  // separator between empty ts and empty val
378→
379→            w = p - q;
380→            firstField = false;
381→        }
382→        if (w < 0 || (size_t)w >= rem) return 0;
383→        q += w; rem -= w;
384→    }
385→
386→    // Write DIO timestamp,value pair only if DIO is enabled
387→    if (dioEnabled) {
388→        if (*hadDIO) {
389→            if (firstField) {
390→                w = snprintf(q, rem, "%u,%u", dioPeek.Timestamp, dioPeek.Values);
391→                firstField = false;
392→            } else {
393→                w = snprintf(q, rem, ",%u,%u", dioPeek.Timestamp, dioPeek.Values);
394→            }
395→        } else {
396→            // Empty DIO: emit two empty fields (ts,val) to match header columns
397→            if (firstField) {
398→                w = snprintf(q, rem, ",");  // [empty_ts],[empty_val] - comma separates the two
399→                firstField = false;
400→            } else {
401→                w = snprintf(q, rem, ",,");  // [sep],[empty_ts],[empty_val]
402→            }
403→        }
404→        if (w < 0 || (size_t)w >= rem) return 0;
405→        q += w; rem -= w;
406→    }
407→    // If DIO disabled, don't output DIO columns at all
408→
409→  
410→    if (rem < 1) return 0;
411→    *q++ = '\n';
412→
413→    return (size_t)(q - out);
414→}
