834→            bool needsFlush = (currentMillis - gSDCardData.lastFlushMillis > 5000 ||
835→                    gSDCardData.totalBytesFlushPending > SD_FLUSH_THRESHOLD) &&
836→                    gSDCardData.totalBytesFlushPending > 0;
837→            if (needsFlush) {
838→                xSemaphoreGive(gSDCardData.wMutex);
