846→                } else {
847→                    // Only reset counter after successful flush
848→                    SD_TakeMutexDebug(gSDCardData.wMutex, "periodic_flush_reset");
849→                    gSDCardData.totalBytesFlushPending = 0;
850→                    gSDCardData.lastFlushMillis = currentMillis;
851→                    xSemaphoreGive(gSDCardData.wMutex);
852→                }
853→            } else {
854→                xSemaphoreGive(gSDCardData.wMutex);
855→            }
856→
857→        }
