864→            }
865→
866→            // Continuous loop for file transfer instead of one chunk per task tick.
867→            // Yields every 1 second to other tasks. Priority boosted to prevent preemption.
868→            // Diagnostic logging added for GitHub #146.
869→
870→            uint32_t totalBytesRead = 0;
871→            uint32_t readCount = 0;
872→
873→            // Boost task priority to match USB tasks for balanced time slicing
874→            TaskHandle_t currentTask = xTaskGetCurrentTaskHandle();
875→            UBaseType_t originalPriority = uxTaskPriorityGet(currentTask);
876→            vTaskPrioritySet(currentTask, 7);  // Same as USB tasks for round-robin scheduling
877→
878→            // Track time for periodic yielding
