 40→/**
 41→ * @brief Generate JSON metadata header with device info (sent once per session)
 42→ *
 43→ * Outputs a JSON object containing device metadata similar to CSV header:
 44→ * {"meta":{"dev":"Nyquist NQ1","sn":"0123456789ABCDEF","tick_hz":1000000}}
 45→ *
 46→ * @param out      Output buffer
 47→ * @param buffSize Size of output buffer
 48→ * @return Bytes written (0 on failure)
 49→ */
 50→static size_t generateJsonHeader(char *out, size_t buffSize) {
 51→    if (!out || buffSize == 0) {
 52→        return 0;
 53→    }
 54→
 55→    const tBoardConfig* boardConfig = (const tBoardConfig*)BoardConfig_Get(BOARDCONFIG_ALL_CONFIG, 0);
 56→    if (!boardConfig) {
 57→        LOG_E("[JSON] Board config is NULL, cannot generate header");
 58→        return 0;
 59→    }
 60→
 61→    uint8_t variant = 0;
 62→    uint64_t serialNum = 0;
 63→    void* pVar = BoardConfig_Get(BOARDCONFIG_VARIANT, 0);
 64→    void* pSer = BoardConfig_Get(BOARDCONFIG_SERIAL_NUMBER, 0);
 65→    if (pVar) variant = *(uint8_t*)pVar;
 66→    if (pSer) serialNum = *(uint64_t*)pSer;
 67→
 68→    // Get timestamp tick rate (0 = timer not initialized, indicates config problem)
 69→    uint32_t tickRate = TimerApi_FrequencyGet(boardConfig->StreamingConfig.TSTimerIndex);
 70→
 71→    // Determine required size dynamically (avoids hardcoded buffer size)
 72→    int need = snprintf(NULL, 0,
 73→        "{\"meta\":{\"dev\":\"%s %u\",\"sn\":\"%016llX\",\"tick_hz\":%u}}\n",
 74→        DAQIFI_PRODUCT_NAME,
 75→        variant,
 76→        (unsigned long long)serialNum,
 77→        tickRate);
 78→    if (need < 0) {
 79→        return 0;
 80→    }
 81→    size_t required = (size_t)need + 1; // +1 for null terminator
 82→    if (required > buffSize) {
 83→        return 0;
 84→    }
 85→
 86→    // Generate compact JSON metadata object
 87→    int written = snprintf(out, buffSize,
 88→        "{\"meta\":{\"dev\":\"%s %u\",\"sn\":\"%016llX\",\"tick_hz\":%u}}\n",
 89→        DAQIFI_PRODUCT_NAME,
 90→        variant,
 91→        (unsigned long long)serialNum,
 92→        tickRate);
 93→
 94→    if (written < 0 || (size_t)written >= buffSize) {
 95→        return 0;
 96→    }
 97→
 98→    return (size_t)written;
 99→}
