166→                    // Null-terminate safely before early return
167→                    if (buffSize > 0) {
168→                        size_t term = startIndex < buffSize ? startIndex : (buffSize - 1);
169→                        charBuffer[term] = '\0';
170→                    }
171→                    return startIndex;
172→                }
173→                startIndex += written;
174→                break;
175→            }
176→            case DaqifiOutMessage_analog_in_data_tag:
177→                encodeADC = true;
178→                break;
179→            case DaqifiOutMessage_digital_data_tag:
