328→    // Encode DIO if needed
329→    if (encodeDIO) {
330→        size_t diStart = startIndex;
331→
332→        int written = snprintf(charBuffer + startIndex,
333→                buffSize - startIndex,
334→                "\"di\":[");
335→        if (written < 0 || written >= (int)(buffSize - startIndex)) {
336→            // Null-terminate safely before early return
337→            if (buffSize > 0) {
338→                size_t term = startIndex < buffSize ? startIndex : (buffSize - 1);
339→                charBuffer[term] = '\0';
