351→
352→            int elemWritten = snprintf(charBuffer + startIndex,
353→                    buffSize - startIndex,
354→                    "{\"ts\":%u, \"mask\":%u, \"val\":%u},",
355→                    state->StreamTrigStamp - data.Timestamp,
356→                    data.Mask,
357→                    data.Values);
358→            if (elemWritten < 0 || elemWritten >= (int)(buffSize - startIndex)) {
359→                break;  // Keep sample for next attempt
360→            }
361→
362→            // Write succeeded - commit by removing sample from queue
363→            startIndex += elemWritten;
364→            DIOSampleList_PopFront(&state->DIOSamples, &data);
365→        }
366→
367→        if (startIndex == diElementsStart) {
368→            // No elements were written; roll back emission of "di":[
369→            startIndex = diStart;
370→        } else {
371→            // Remove trailing comma and close array
372→            if (startIndex > 0 && charBuffer[startIndex - 1] == ',') {
373→                startIndex -= 1;
374→            }
375→            int closeWritten = snprintf(charBuffer + startIndex,
376→                    buffSize - startIndex,
377→                    "],\n");
378→            if (closeWritten < 0 || closeWritten >= (int)(buffSize - startIndex)) {
379→                // Null-terminate safely before early return
