452→    }
453→
454→    // Close the JSON object
455→    if (startIndex >= 2 && charBuffer[startIndex - 2] == ',') {
456→        startIndex -= 2; // Remove trailing comma
457→    }
458→    int written = snprintf(charBuffer + startIndex,
