1692→static scpi_result_t SCPI_StopStreaming(scpi_t * context) {
1693→    StreamingRuntimeConfig * pRunTimeStreamConfig = BoardRunTimeConfig_Get(
1694→            BOARDRUNTIME_STREAMING_CONFIGURATION);
1695→
1696→    if (pRunTimeStreamConfig) {
1697→        pRunTimeStreamConfig->IsEnabled = false;
1698→    }
1699→
1700→    Streaming_UpdateState();
1701→
1702→    // Close SD card file if logging was enabled
1703→    sd_card_manager_settings_t* pSDCardRuntimeConfig = BoardRunTimeConfig_Get(BOARDRUNTIME_SD_CARD_SETTINGS);
1704→    if (pSDCardRuntimeConfig != NULL &&
1705→        pSDCardRuntimeConfig->enable && pSDCardRuntimeConfig->mode == SD_CARD_MANAGER_MODE_WRITE) {
1706→        // Set mode to NONE and update to trigger file close (DEINIT → UNMOUNT → close)
1707→        pSDCardRuntimeConfig->mode = SD_CARD_MANAGER_MODE_NONE;
1708→        sd_card_manager_UpdateSettings(pSDCardRuntimeConfig);
1709→        // Give SD card manager task time to close the file
1710→        vTaskDelay(pdMS_TO_TICKS(100));
1711→    }
1712→
1713→    // Reset encoder state so next session gets fresh headers
1714→    csv_ResetEncoder();
1715→    json_ResetEncoder();
1716→
1717→    return SCPI_RES_OK;
1718→}
