351→/**
352→ * @brief Encodes a DaqifiOutMessage into the provided buffer.
353→ * 
354→ * This helper function handles the encoding of the DaqifiOutMessage structure into
355→ * the provided buffer. It updates the buffer offset to track the position for
356→ * the next encoding operation.
357→ * 
358→ * @param message        Pointer to the DaqifiOutMessage to encode.
359→ * @param pBuffer        Pointer to the output buffer.
360→ * @param buffSize       Total size of the output buffer.
361→ * @param pBuffOffset    Pointer to the current buffer offset (will be updated).
362→ * @return true          If encoding was successful.
363→ * @return false         If encoding failed due to insufficient buffer space or other errors.
364→ */
365→static bool encode_message_to_buffer(DaqifiOutMessage* message, uint8_t* pBuffer, size_t buffSize, uint32_t* pBuffOffset) {
366→    pb_ostream_t stream = pb_ostream_from_buffer(pBuffer + *pBuffOffset, buffSize - *pBuffOffset);
367→    if (!pb_encode_delimited(&stream, DaqifiOutMessage_fields, message)) {
368→        return false;
369→    }
370→    *pBuffOffset += stream.bytes_written;
371→    return true;
372→}
