386→
387→    DaqifiOutMessage message = DaqifiOutMessage_init_default;
388→    uint32_t bufferOffset = 0;
389→    size_t i = 0;
390→    if (buffSize < Nanopb_EncodeLength(fields)) {
391→        return 0;
392→    }
393→    if (pBuffer == NULL) {
