411→                AInPublicSampleList_t *pPublicSampleList;
412→                while (queueSize > 0) {
413→                    // Retrieve the next sample from the queue
414→
415→                    if (!AInSampleList_PopFront(&pPublicSampleList)) { //takes approx 4.2us
416→                        break;
417→                    }
418→
419→                    if (pPublicSampleList == NULL)
