428→                        if (message.analog_in_data_count > maxDataIndex)
429→                            break;  // Array full
430→                        // Use sequential packing
431→                        message.analog_in_data[message.analog_in_data_count] = data.Value;
432→                        message.analog_in_data_count++;
433→                    }
434→
435→                     AInSampleList_FreeToPool(pPublicSampleList);  // Use pool instead of vPortFree
436→
437→                    if (message.analog_in_data_count > 0) {
438→                        //time stamp of all the samples in a list should be same, so using anyone should be fine
439→                        message.msg_time_stamp = data.Timestamp;
440→                        if (!encode_message_to_buffer(&message, pBuffer, buffSize, &bufferOffset)) { //takes 248 us
441→                            return 0; // Return 0 if encoding fails
442→                        }
443→
444→                        // Check if buffer has enough space for another message
445→                        if (bufferOffset + Nanopb_EncodeLength(fields) > buffSize) {
446→                            return bufferOffset; // Stop if the buffer is full
447→                        }
448→
449→                    }
